import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_SALTA: Article[] = [
  { id: 'const-salta-art-1', lawId: 'const-salta', number: '1', title: 'Organizacion del Estado y la Sociedad', text: `La Provincia de Salta, como parte integrante de la República Argentina, organiza su gobierno bajo el sistema republicano y representativo. Reafirma su inquebrantable unidad de destino con las demás provincias, territorios nacionales y tierras aún irredentas, en el marco del federalismo. Esta Constitución promueve la democracia social de derecho, basada en el trabajo de personas libres, iguales y solidarias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-salta-art-2', lawId: 'const-salta', number: '2', title: '', text: `La soberanía reside en el pueblo, quien la ejerce a través de sus representantes y demás autoridades legítimamente constituidas y por sí, de acuerdo con las formas de participación que la presente Constitución establece. Esta Constitución no pierde vigencia aún cuando por acto violento o de cualquier naturaleza se llegue a interrumpir su observancia. En tal caso, tan pronto como el pueblo recobre la libertad, se restablecerá su imperio y serán juzgados los responsables y quienes hubieren colaborado, los que, además, quedan inhabilitados a perpetuidad para ocupar cargos públicos, sean éstos electivos o no, y son declarados infames traidores a la soberanía popular. El no acatamiento de las órdenes y actos de tales usurpadores será legítimo. Los actos y leyes que realicen y dicten podrán ser declarados nulos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 1, segments: [], amendments: [] },
  { id: 'const-salta-art-3', lawId: 'const-salta', number: '3', title: '', text: `A los poderes públicos corresponde: 1) Ejercer los derechos y competencias no delegados al gobierno federal, para hacer plenamente efectivo el sistema federal adoptado en la Constitución Nacional. 2) Promover un federalismo de concertación con el gobierno federal y entre las provincias, con la finalidad de satisfacer intereses comunes y para participar en organismos de consulta y decisión de nivel federal y establecer relaciones intergubernamentaleso interjurisdiccionales, mediante tratados y convenios. 3) Practicar en los lugares transferidos por compra o cesión al gobierno federal las potestades provinciales que no obstaculicen el cumplimiento del objetivo de la utilidad nacional de los mismos. 4) Concertar con la Nación regímenes de coparticipación impositiva. 5) Procurar y gestionar la desconcentración de la administración nacional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 2, segments: [], amendments: [] },
  { id: 'const-salta-art-4', lawId: 'const-salta', number: '4', title: '', text: `Los poderes públicos no pueden delegar facultades conferidas por esta Constitución, ni atribuirse otras que las expresamente acordadas por ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 3, segments: [], amendments: [] },
  { id: 'const-salta-art-5', lawId: 'const-salta', number: '5', title: '', text: `El Estado y, en su caso, sus funcionarios y empleados son responsables por los daños que ocasionen. Esta responsabilidad se extiende a los errores judiciales. El Estado Provincial es plenamente justiciable sin necesidad de autorización previa, en los términos de las leyes pertinentes. Los embargos no pueden recaer sobre los bienes afectados a la función asistencial del Estado ni exceder el veinticinco por ciento de los recursos ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 4, segments: [], amendments: [] },
  { id: 'const-salta-art-6', lawId: 'const-salta', number: '6', title: '', text: `Los límites territoriales de la Provincia son los que por derecho le corresponden. La ley que autorice su modificación requiere los dos tercios de votos del número total de miembros de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 5, segments: [], amendments: [] },
  { id: 'const-salta-art-7', lawId: 'const-salta', number: '7', title: '', text: `La ciudad de Salta es la capital de la Provincia y en ella residen las autoridades que ejercen el gobierno. Por ley puede disponerse el traslado de la capital a otro lugar del territorio provincial. La misma requiere el voto de los dos tercios del total de los miembros de cada Cámara. Dicha ley no importa reforma de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 6, segments: [], amendments: [] },
  { id: 'const-salta-art-8', lawId: 'const-salta', number: '8', title: '', text: `El territorio de la Provincia se divide en departamentos y municipios. El Estado Provincial promueve la integración social, económica y cultural de las regiones con características e intereses comunes, mediante la creación de instituciones que tengan a su cargo la planificación y ejecución del desarrollo regional, con participación en los organismos del Gobierno.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 7, segments: [], amendments: [] },
  { id: 'const-salta-art-9', lawId: 'const-salta', number: '9', title: '', text: `El Preámbulo resume los fines del Estado Provincial y las aspiraciones comunes de sus habitantes. Su texto es fuente de interpretación y orientación para establecer el alcance, significado y finalidad de todas las cláusulas de esta Constitución. No puede ser invocado para ampliar las competencias de los poderes públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 8, segments: [], amendments: [] },
  { id: 'const-salta-art-10', lawId: 'const-salta', number: '10', title: '', text: `La vida desde su concepción, la dignidad y la integridad física y moral de la persona son intangibles. Su respeto y protección es deber de todos y en especial de los poderes públicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 9, segments: [], amendments: [] },
  { id: 'const-salta-art-11', lawId: 'const-salta', number: '11', title: 'Libertad de Culto', text: `CULTO CATOLICO. Es inviolable en el territorio de la Provincia el derecho de todos para ejercer libre y públicamente su culto, según los dictados de su conciencia y sin otras restricciones que las que prescriben la moral y el orden público. Nadie puede ser obligado a declarar la religión que profesa. El Gobierno de la Provincia coopera al sostenimiento y protección del culto católico, apostólico y romano.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 10, segments: [], amendments: [] },
  { id: 'const-salta-art-12', lawId: 'const-salta', number: '12', title: '', text: `Ningún habitante está obligado a hacer lo que la ley no manda, ni privado de lo que ella no prohibe. Las acciones privadas de los hombres, que de ningún modo ofendan a la moral o al orden público ni perjudiquen los derechos de terceros, están reservadas a Dios y exentas de la autoridad de los magistrados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 11, segments: [], amendments: [] },
  { id: 'const-salta-art-13', lawId: 'const-salta', number: '13', title: 'Principio de Igualdad', text: `Todas las personas son iguales ante la ley, sin distinción por razón de nacimiento, raza, sexo, religión, opinión o cualquier otra condición o circunstancia personal o social. No se admiten fueros personales. Quedan suprimidos todos los títulos y tratamientos honoríficos o de excepción para los cuerpos, magistrados y funcionarios de la Provincia, cualquiera sea su investidura. Los poderes públicos aseguran las condiciones para que la libertad y la igualdad de las personas sean reales y efectivas, procurando remover los obstáculos que impidan o dificulten su plenitud. Garantízase la igualdad del hombre y la mujer y el ejercicio pleno de sus derechos económicos, sociales, culturales y políticos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 12, segments: [], amendments: [] },
  { id: 'const-salta-art-14', lawId: 'const-salta', number: '14', title: '', text: `La Provincia reconoce y garantiza los derechos inviolables de la persona, sea como individuo, sea en el seno de las formaciones sociales donde aquélla desarrolle su personalidad, y exige el cumplimiento de los deberes inexcusables de solidaridad política, económica y social.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 13, segments: [], amendments: [] },
  { id: 'const-salta-art-15', lawId: 'const-salta', number: '15', title: '', text: `I. La Provincia reconoce la preexistencia étnica y cultural de los pueblos indígenas que residen en el territorio de Salta. Reconoce la personalidad de sus propias comunidades y sus organizaciones a efectos de obtener la personería jurídica y la legitimación para actuar en las instancias administrativas y judiciales de acuerdo con lo que establezca la ley. Créase al efecto un registro especial. Reconoce y garantiza el respeto a su identidad, el derecho a una educación bilingüe e intercultural, la posesión y propiedad comunitaria de las tierras fiscales que tradicionalmente ocupan, y regula la entrega de otras aptas y suficientes para el desarrollo humano. Ninguna de ellas será enajenable, transmisible ni susceptible de gravámenes ni embargos. Asegura su participación en la gestión referida a sus recursos naturales y demás intereses que los afecten de acuerdo a la ley. II. El Gobierno Provincial genera mecanismos que permitan, tanto a los pobladores indígenas como no indígenas, con su efectiva participación, consensuar soluciones en lo relacionado con la tierra fiscal, respetando los derechos de terceros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 14, segments: [], amendments: [] },
  { id: 'const-salta-art-16', lawId: 'const-salta', number: '16', title: '', text: `REGLAMENTACION. OPERATIVIDAD. Todos los habitantes gozan de los derechos y garantías consagrados por esta Constitución de conformidad con las leyes que reglamenten razonablemente su ejercicio. Los principios, declaraciones, derechos y garantías contenidos en ella no pueden ser alterados por disposición alguna. Tales enunciaciones no son negatorias de otros derechos y garantías no enumerados, pero que nacen de la libertad, igualdad y dignidad de la persona humana, de los requerimientos de la justicia social, de los principios de la democracia social de derecho, de la soberanía del pueblo y de la forma republicana de gobierno. Tales derechos tienen plena operatividad, sin que su ejercicio pueda ser menoscabado por ausencia o insuficiencia de reglamentación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 15, segments: [], amendments: [] },
  { id: 'const-salta-art-17', lawId: 'const-salta', number: '17', title: '', text: `Todos los habitantes de la Provincia son, por naturaleza, libres y tienen derecho a defenderse y ser protegidos en su vida, libertad, reputación, seguridad, actividad, prosperidad, intimidad personal y familiar, así como en su propia imagen. Ningún servicio personal es exigible sino en virtud de ley o sentencia fundada en ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 16, segments: [], amendments: [] },
  { id: 'const-salta-art-18', lawId: 'const-salta', number: '18', title: '', text: `Es inviolable la defensa de la persona y sus derechos en sede judicial, administrativa y en el seno de las entidades de derecho privado. La ley prevé la asistencia letrada gratuita a las personas de modestos recursos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 17, segments: [], amendments: [] },
  { id: 'const-salta-art-19', lawId: 'const-salta', number: '19', title: '', text: `La libertad personal es inviolable y nadie puede ser detenido sin orden de autoridad judicial, salvo el caso de flagrante delito y demás excepciones extraordinarias que prevé la ley. Toda restricción de la libertad física se dispone dentro de los límites absolutamente indispensables para la investigación del ilícito o para evitar que el imputado pueda eludir la acción de la justicia o en relación con la gravedad de los hechos. Todo detenido debe ser notificado en el acto de la detención, en forma comprensible y fehaciente, de la causa de la misma y conducido de inmediato ante el juez competente, quien ordena inmediatamente un examen psicofísico del mismo. El Estado garantiza la asistencia letrada del imputado en las diligencias policiales y judiciales, y la asistencia de oficio cuando no se designe defensor particular. La ley regula la excarcelación de oficio. Las torturas, tratos inhumanos o degradantes comprometen la responsabilidad de los agentes públicos, funcionarios y jueces que los realicen, consientan o se abstengan de denunciarlos. La ley establece las sanciones para estos casos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 18, segments: [], amendments: [] },
  { id: 'const-salta-art-20', lawId: 'const-salta', number: '20', title: '', text: `PRESUNCION DE INOCENCIA. JUEZ COMPETENTE. La responsabilidad penal es personal. Nadie es considerado culpable hasta la sentencia definitiva ni puede ser penado o sancionado por acciones u omisiones que, al momento de producirse, no constituyan delito, falta o contravención. Todos tienen derecho a ser juzgados por juez previamente competente. Nadie puede ser juzgado por comisiones o tribunales especiales, sea cual fuere la denominación que se les dé. Nadie será acusado o juzgado dos veces por un mismo delito, falta o contravención. La ley penal más benigna se aplica retroactivamente. Ninguna norma puede agravar la situación del imputado, procesado o condenado. La duda actúa en favor del imputado. En causa criminal nadie puede ser obligado a declarar contra sí mismo, sus ascendientes, descendientes, cónyuge, hermano, afines hasta segundo grado, tutores, pupilos o personas de ostensible trato familiar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 19, segments: [], amendments: [] },
  { id: 'const-salta-art-21', lawId: 'const-salta', number: '21', title: '', text: `Las penas privativas de la libertad tienen como fin la reeducación y la reinserción social de quienes las sufren. Las cárceles son sanas y limpias. Todo penado tiene el deber de trabajar con derecho a una justa remuneración y a los beneficios de la seguridad social, como asimismo a mantener relaciones familiares y acceder a la instrucción. Los detenidos están separados de los procesados y éstos de los condenados. Los menores y mujeres son alojados en establecimientos separados. Los condenados por tribunales de la Provincia cumplen la pena en cárceles de su jurisdicción. Las excepciones a estas previsiones sólo pueden disponerse por decisión judicial fundada o por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 20, segments: [], amendments: [] },
  { id: 'const-salta-art-22', lawId: 'const-salta', number: '22', title: '', text: `Son inviolables el domicilio, los papeles y registros de datos privados, la correspondencia epistolar y las comunicaciones de cualquier índole. Sólo pueden ser allanados, intervenidos, interceptados o registrados, en virtud de orden escrita de juez competente. El allanamiento de domicilio en horas de la noche es excepcional, el magistrado que lo dispone debe fundar la decisión. Las autoridades policiales proporcionan antecedentes penales o judiciales de los habitantes exclusivamente en los casos previstos por la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 21, segments: [], amendments: [] },
  { id: 'const-salta-art-23', lawId: 'const-salta', number: '23', title: 'Libertad de Expresion', text: `Todos tienen libertad de expresar y difundir, sin censura previa, sus pensamientos, ideas, opiniones y críticas mediante la palabra oral o escrita, por cualquier medio de comunicación, así como la libertad de buscar, recibir y transmitir información. Todos tienen derecho a la libre producción y creación intelectual, literaria, artística y científica. Ninguna autoridad provincial o municipal dicta leyes, decretos u ordenanzas que en cualquier forma tiendan a restringir directa o encubiertamente el ejercicio de la libertad de expresión. Las instalaciones y equipos de los medios de difusión no pueden ser objeto de imposiciones extraordinarias, ni de clausura, confiscaciones o decomisos. Toda norma en contrario es absolutamente nula. Todo habitante que, por causa de una información inexacta o agraviante, sufra perjuicio, tiene el derecho a efectuar gratuitamente por el mismo medio de comunicación su rectificación o respuesta. En caso de negativa el afectado puede recurrir a la instancia judicial, la que debe expedirse en trámite sumarísimo. Se excluye de este derecho a los funcionarios por informaciones referidas a su desempeño o función. Los delitos cometidos en uso de la libertad de expresión son juzgados en procedimiento ordinario y sancionados con arreglo al Código Penal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 22, segments: [], amendments: [] },
  { id: 'const-salta-art-24', lawId: 'const-salta', number: '24', title: '', text: `Esta Constitución garantiza a todos los habitantes el derecho de enseñar y aprender.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 23, segments: [], amendments: [] },
  { id: 'const-salta-art-25', lawId: 'const-salta', number: '25', title: '', text: `Queda asegurado a todas las personas el derecho de reunión pacífica para tratar asuntos públicos o privados, siempre que no turben el orden público, así como también el de peticionar individual o colectivamente ante todas o cada una de las autoridades. En ningún caso una reunión de personas puede atribuirse la representación de los derechos del pueblo, ni peticionar en su nombre.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 24, segments: [], amendments: [] },
  { id: 'const-salta-art-26', lawId: 'const-salta', number: '26', title: 'Libertad de Asociacion', text: `Todas las personas tienen derecho de asociarse libremente con fines lícitos, sin necesidad de autorización previa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 25, segments: [], amendments: [] },
  { id: 'const-salta-art-27', lawId: 'const-salta', number: '27', title: 'Derecho de Transito', text: `Todos los habitantes que se encuentren legalmente en el territorio de la Nación tienen el derecho de entrar, permanecer, transitar y salir de la Provincia, llevando sus bienes y sin perjuicio del derecho de terceros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 26, segments: [], amendments: [] },
  { id: 'const-salta-art-28', lawId: 'const-salta', number: '28', title: '', text: `La libertad de trabajo y del ejercicio de cualquier actividad económica o profesional es un derecho asegurado a toda persona, siempre que no sea contraria al orden público o al derecho de terceros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 27, segments: [], amendments: [] },
  { id: 'const-salta-art-29', lawId: 'const-salta', number: '29', title: '', text: `Todos los habitantes de la Provincia son admisibles en los empleos públicos sin otra condición que la idoneidad. La ley determina los casos en que se requiera la ciudadanía.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 28, segments: [], amendments: [] },
  { id: 'const-salta-art-30', lawId: 'const-salta', number: '30', title: '', text: `DEFENSA DE LA CALIDAD DE VIDA. Todos tienen el deber de conservar el medio ambiente equilibrado y armonioso, así como el derecho a disfrutarlo. Los poderes públicos defienden y resguardan el medio ambiente en procura de mejorar la calidad de vida, previenen la contaminación ambiental y sancionan las conductas contrarias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 29, segments: [], amendments: [] },
  { id: 'const-salta-art-31', lawId: 'const-salta', number: '31', title: '', text: `Los consumidores y usuarios de bienes y servicios tienen derecho, en la relación de consumo, a la protección de su salud, seguridad e intereses económicos ; a una información adecuada y veraz ; a la libertad de elección y a condiciones de trato equitativo y digno. Las autoridades aseguran la protección de esos derechos, la educación para el consumo, la defensa de la competencia contra toda forma de distorsión de los mercados, el control de los monopolios naturales y legales, la calidad y eficiencia de los servicios públicos y la constitución de asociaciones de consumidores y usuarios. La legislación regula la publicidad para evitar inducir a conductas adictivas o perjudiciales o promover la automedicación y establece sanciones contra los mensajes que distorsionen la voluntad de compra del consumidor mediante técnicas que la ley determine como inadecuadas. La legislación establece procedimientos eficaces y expeditos para la prevención y solución de conflictos y los marcos regulatorios de los servicios públicos de competencia provincial, previendo la necesaria participación de los consumidores, usuarios, asociaciones que los representen y municipios, en los órganos de control.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 30, segments: [], amendments: [] },
  { id: 'const-salta-art-32', lawId: 'const-salta', number: '32', title: '', text: `La familia es el núcleo primario y fundamental de la sociedad. Los poderes públicos protegen y reconocen sus derechos para el cumplimiento de sus fines. La madre goza de especial protección y las condiciones laborales deben permitirle el cumplimiento de su esencial función familiar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 31, segments: [], amendments: [] },
  { id: 'const-salta-art-33', lawId: 'const-salta', number: '33', title: '', text: `El Estado asegura la protección de la infancia, cubriendo sus necesidades afectivas, ambientales, de educación, salud, alimentación y recreación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 32, segments: [], amendments: [] },
  { id: 'const-salta-art-34', lawId: 'const-salta', number: '34', title: '', text: `El Estado promueve el desarrollo integral de los jóvenes, posibilita su perfeccionamiento y su aporte creativo. Propende a lograr una plena formación cultural, cívica y laboral, que desarrolle la conciencia nacional, que lo arraigue a su medio y que asegure su participación efectiva en las actividades comunitarias y políticas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 33, segments: [], amendments: [] },
  { id: 'const-salta-art-35', lawId: 'const-salta', number: '35', title: '', text: `Se reconoce a la ancianidad el derecho a una existencia digna, considerándola como una etapa fecunda de la vida, susceptible de una integración activa sin marginación, y es deber del Estado proteger, asistir y asegurar sus derechos. La Provincia procura a los habitantes de la tercera edad: 1) La asistencia. 2) La vivienda. 3) La alimentación. 4) El vestido. 5) La salud física. 6) La salud moral. 7) El esparcimiento. 8) El trabajo acorde con sus condiciones físicas. 9) La tranquilidad. 10) El respeto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 34, segments: [], amendments: [] },
  { id: 'const-salta-art-36', lawId: 'const-salta', number: '36', title: '', text: `Los poderes públicos brindan a los discapacitados físicos, sensoriales o psíquicos la asistencia apropiada, con especial énfasis en la terapia rehabilitadora y en la educación especializada. Se los ampara para el disfrute de los derechos que les corresponden como miembros plenos de la comunidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 35, segments: [], amendments: [] },
  { id: 'const-salta-art-37', lawId: 'const-salta', number: '37', title: 'De la Vivienda', text: `Los poderes públicos facilitan el acceso de los sectores de menores ingresos a una vivienda digna y promueven la constitución del asiento del hogar como bien de familia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 36, segments: [], amendments: [] },
  { id: 'const-salta-art-38', lawId: 'const-salta', number: '38', title: '', text: `La seguridad social cubre las necesidades esenciales de las personas frente a las contingencias limitativas en su vida individual o social. El Estado fiscaliza el efectivo cumplimiento de las normas relativas a la seguridad social y estimula los sistemas e instituciones creados por la comunidad con el fin de superar sus carencias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 37, segments: [], amendments: [] },
  { id: 'const-salta-art-39', lawId: 'const-salta', number: '39', title: '', text: `El seguro social se extiende a toda la población y tiene el carácter de integral e irrenunciable, coordinándose la acción y legislación provincial con la nacional. Los interesados participan en el gobierno del sistema que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 38, segments: [], amendments: [] },
  { id: 'const-salta-art-40', lawId: 'const-salta', number: '40', title: '', text: `El régimen jubilatorio provincial es único para todas las personas y asegura la equidad y la inexistencia de privilegios que importen desigualdades que no respondan a causas objetivas y razonables. El haber previsional debe ser móvil y guardar estrecha relación con la remuneración del mismo cargo en actividad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 39, segments: [], amendments: [] },
  { id: 'const-salta-art-41', lawId: 'const-salta', number: '41', title: '', text: `La salud es un derecho inherente a la vida y su preservación es un deber de cada persona. Es un bien social. Compete al Estado el cuidado de la salud física, mental y social de las personas, y asegurar a todos la igualdad de prestaciones ante idénticas necesidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 40, segments: [], amendments: [] },
  { id: 'const-salta-art-42', lawId: 'const-salta', number: '42', title: '', text: `El Estado elabora el Plan de Salud Provincial con la participación de los sectores socialmente interesados, contemplando la promoción, prevención, restauración y rehabilitación de la salud, estableciendo las prioridades con un criterio de justicia social y utilización racional de los recursos. Coordina con la Nación y las otras provincias, las políticas pertinentes, propendiendo a la integración regional en el aspecto asistencial, en la investigación y en el control de las patologías que les son comunes. El sistema de salud asegura el principio de libre elección del profesional.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 41, segments: [], amendments: [] },
  { id: 'const-salta-art-43', lawId: 'const-salta', number: '43', title: '', text: `El trabajo, en sus diversas formas, es un derecho y un deber en la realización de la persona y en su activa participación en la construcción del bien común. Por su alta finalidad social goza de la especial protección de las leyes, que deberán procurar al trabajador las condiciones de una existencia digna y libre. La Provincia reconoce al trabajo como la fuente genuina del progreso vy bienestar de todos sus habitantes. A través de él las personas manifiestan su capacidad creadora.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 42, segments: [], amendments: [] },
  { id: 'const-salta-art-44', lawId: 'const-salta', number: '44', title: '', text: `Los poderes públicos, ejerciendo las facultades propias del poder de policía, reconocen y resguardan los siguientes derechos del trabajador: 1) Derecho a trabajar. 2) Derecho a una retribución justa. 3) Derecho a la capacitación. 4) Derecho a condiciones dignas de trabajo. 5) Derecho a la preservación de la salud. 6) Derecho al bienestar. 7) Derecho a la seguridad social. 8) Derecho a la protección de la familia. 9) Derecho al mejoramiento económico. 10) Derecho a la defensa de los intereses profesionales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 43, segments: [], amendments: [] },
  { id: 'const-salta-art-45', lawId: 'const-salta', number: '45', title: 'Procedimiento Laboral', text: `Las actuaciones ante la justicia laboral son gratuitas para el trabajador o sus derecho- habientes. Se propende a que el procedimiento sea oral, sumario y sustanciado ante tribunales colegiados, con las limitaciones, en materia de recursos, que señala la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 44, segments: [], amendments: [] },
  { id: 'const-salta-art-46', lawId: 'const-salta', number: '46', title: '', text: `Los trabajadores y los dirigentes sindicales no pueden ser discriminados ni perjudicados por sus actividades gremiales. Las organizaciones profesionales o gremiales son reconocidas jurídicamente para el ejercicio de los derechos y el cumplimiento de los deberes que establecen las leyes de la Nación y de la Provincia. Los sindicatos no pueden ser intervenidos ni sus sedes clausuradas, ni sus fondos bloqueados sino por orden de Juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 45, segments: [], amendments: [] },
  { id: 'const-salta-art-47', lawId: 'const-salta', number: '47', title: '', text: `La educación es un derecho de la persona y un deber de la familia y de la sociedad, a la que asiste el Estado como función social prioritaria, primordial e insoslayable.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 46, segments: [], amendments: [] },
  { id: 'const-salta-art-48', lawId: 'const-salta', number: '48', title: 'Fin de la Educacion', text: `El fin de la educación es el desarrollo integral, armonioso y permanente de la persona en la formación de un hombre capacitado para convivir en una sociedad democrática participativa basada en la libertad y la justicia social.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 47, segments: [], amendments: [] },
  { id: 'const-salta-art-49', lawId: 'const-salta', number: '49', title: 'Sistema Educacional', text: `El sistema educacional contempla las siguientes bases: *La educación pública estatal es gratuita, común, asistencial y obligatoria en el nivel que fije la ley. * Promueve el desarrollo de la capacidad crítica del educando. * Difunde y fortalece los principios reconocidos por esta Constitución. * Consolida la familia y garantiza la libre elección del establecimiento educacional. * Establece el conocimiento de la realidad provincial, nacional, latinoamericana y universal. * Promueve el empleo de los medios y técnicas de comunicación en beneficio de la educación popular. * Impulsa la educación media, técnica y superior y la investigación científica y tecnológica. * Integra educación y trabajo, capacitando para las tareas vinculadas a los tipos de producción característicos de cada zona. * Los padres y en su caso los tutores, tienen derecho a que sus hijos o pupilos reciban en la escuela pública la educación religiosa que esté de acuerdo con sus propias convicciones. * Promueve la educación del adulto y sostiene la educación especial. * Las personas y asociaciones tienen derecho a la creación de instituciones educativas ajustadas a los principios de esta Constitución. Las mismas son reconocidas, supervisadas y apoyadas en su caso por el Estado. * Tiende a una mayor participación y desconcentración. * Difunde la educación sanitaria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 48, segments: [], amendments: [] },
  { id: 'const-salta-art-50', lawId: 'const-salta', number: '50', title: '', text: `El Despacho de los asuntos de Educación está a cargo de un Ministerio específico, que ejecuta la política educacional, cultural, científica y tecnológica. Pueden crearse Consejos Escolares integrados por padres de alumnos para la atención inmediata de los requerimientos esenciales de la Comunidad Educativa, sin ingerencia en la conducción técnica de la enseñanza .`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 49, segments: [], amendments: [] },
  { id: 'const-salta-art-51', lawId: 'const-salta', number: '51', title: '', text: `El Estado Provincial asegura la formación docente y estimula la vocación de perfeccionamiento a través de sistemas que procuren mejorar la calidad de enseñanza. La ley, a través del Estatuto del Docente, garantiza sus derechos y determina sus deberes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 50, segments: [], amendments: [] },
  { id: 'const-salta-art-52', lawId: 'const-salta', number: '52', title: '', text: `El Estado asegura a todos los habitantes el derecho a acceder a la cultura y elimina toda forma de discriminación ideológica en la creación cultural. Promueve las manifestaciones culturales, personales o colectivas y aquéllas que afirmen el sentido nacional y latinoamericano. El acervo histórico, arqueológico, artístico y documental forma parte del patrimonio cultural de la Provincia y está bajo la guarda del Estado. Las manifestaciones culturales y tradicionales de reconocido arraigo y trascendencia popular son protegidas y promocionadas por el Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 51, segments: [], amendments: [] },
  { id: 'const-salta-art-53', lawId: 'const-salta', number: '53', title: '', text: `Todos los ciudadanos tienen derecho a asociarse libremente con fines políticos, en partidos y movimientos. Los partidos políticos son instrumentos de participación con los que se expresa la voluntad política del Pueblo para integrar los poderes del Estado. Su organización, estatutos y finalidades, deben respetar los principios democráticos. El Estado les presta ayuda para la formación y capacitación de sus dirigentes, teniendo en cuenta el caudal electoral del último comicio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 52, segments: [], amendments: [] },
  { id: 'const-salta-art-54', lawId: 'const-salta', number: '54', title: '', text: `Compete exclusivamente a los partidos políticos y frentes electorales postular candidatos para las elecciones populares. Los procedimientos de designación de los mismos son democráticos y con manifestación pública de principios y plataformas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 53, segments: [], amendments: [] },
  { id: 'const-salta-art-55', lawId: 'const-salta', number: '55', title: '', text: `NATURALEZA Y CARACTERES. El sufragio es un derecho que corresponde a todo ciudadano y una función política que tiene el deber de ejercitar, con arreglo a esta Constitución y a la ley. El voto es universal, secreto y obligatorio. Son electores los ciudadanos inscriptos en el registro cívico electoral, vigente a la época de la respectiva elección y domiciliados en el territorio provincial. Los extranjeros son electores en el orden municipal, en las condiciones que determine la ley. *Art. 56.- La Ley establece el Régimen Electoral. En caso de que la misma opte por el de mayoría deberá asegurar la representación proporcional de las minorías. Su reforma requerirá del voto de los dos tercios de los miembros de cada Cámara. Los senadores son elegidos por el pueblo de los Departamentos de la Provincia, formando, cada uno de ellos, a ese efecto, un distrito electoral. Los diputados son elegidos por el pueblo de los distritos electorales formados por uno o más Departamentos, y constituidos como lo disponga la Ley Electoral, ajustada a la finalidad de procurar que, en cada distrito se perfeccione la representación de las minorías y el respeto por las realidades poblacionales, preservando la identidad y proximidad entre los electores y sus elegidos. La autoridad comicial dispone de la fuerza pública a los efectos de asegurar la regularidad del acto. Todos los electores gozan, durante el acto comicial, de inmunidad de arresto, salvo el caso de flagrante delito o de orden de autoridad competente. El Pode Ejecutivo puede suspender el comicio excepcionalmente por fuerza mayor, de conformidad a los casos determinados por Ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 54, segments: [], amendments: [] },
  { id: 'const-salta-art-57', lawId: 'const-salta', number: '57', title: '', text: `Toda falta, acto de fraude, coacción, soborno, cohecho o intimidación ejercidos contra los electores antes, durante o después del acto electoral son considerados atentados contra el derecho y la libertad electoral y penados con prisión inconmutable. La acción que nace de estos hechos es popular y se puede ejercer hasta un año después de haber sido cometidos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 55, segments: [], amendments: [] },
  { id: 'const-salta-art-58', lawId: 'const-salta', number: '58', title: '', text: `El Tribunal Electoral permanente de la Provincia es presidido por el Presidente de la Corte de Justicia e integrado por dos jueces de la misma y dos de segunda instancia, designados por sorteo y: 1) Dispone lo necesario para la organización y funcionamiento de los comicios. 2) Oficializa candidaturas con aprobación de las boletas que se utilicen para los comicios. 3) Practica el escrutinio definitivo, proclama a los electos y otorga sus diplomas. Establece los suplentes que entrarán en funciones, de acuerdo con la ley. 4) Juzga la validez de las elecciones. 5) Confecciona, en su caso, registros cívicos electorales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 56, segments: [], amendments: [] },
  { id: 'const-salta-art-59', lawId: 'const-salta', number: '59', title: '', text: `Se reconoce a los ciudadanos la iniciativa popular para la presentación de proyectos de ley, que deben ser avalados en las condiciones prescriptas por la ley. No pueden plantearse por vía de iniciativa popular los asuntos concernientes a la aprobación de tratados, presupuesto, creación o derogación de tributos provinciales, a la prerrogativa de gracia y reforma de la Constitución. REFERENDUM. Las cuestiones de gobierno y el mantenimiento, reforma o derogación de normas jurídicas de significativa importancia, pueden ser sometidas a la consideración del cuerpo electoral, mediante referéndum. La validez y eficacia del referéndum requiere: 1) Convocatoria al cuerpo electoral, dispuesta por ley. 2) Que los votos emitidos superen el cincuenta por ciento de los electores inscriptos en los registros cívicos electorales. 3) Que la decisión corresponda a la mayoría absoluta de los votos válidos emitidos. Los poderes públicos realizan la publicidad con carácter estrictamente institucional y facilitan a los partidos políticos en forma equitativa, los medios para que den a conocer sus posiciones. No es admisible el referéndum para normas tributarias, presupuestarias o de gracia. La decisión del electorado es obligatoria para todos los poderes públicos y, en su caso, se promulga y se publica.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 57, segments: [], amendments: [] },
  { id: 'const-salta-art-61', lawId: 'const-salta', number: '61', title: '', text: `La administración pública, sus funcionarios y agentes sirven exclusivamente a los intereses del Pueblo. Actúa de acuerdo a los principios de eficacia, jerarquía, desconcentración, coordinación, imparcialidad, sujeción al orden jurídico y publicidad de normas y actos. La descentralización administrativa es dispuesta siempre por ley, atendiendo a los intereses y necesidades de las diferentes regiones de la Provincia. La administración pública se ajusta al principio de centralización normativa y desconcentración operativa. Los funcionarios públicos, para ocupar sus cargos, juran fidelidad a la Patria y lealtad a la Constitución Nacional y a la Presente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 58, segments: [], amendments: [] },
  { id: 'const-salta-art-62', lawId: 'const-salta', number: '62', title: '', text: `Es incompatible el desempeño simultáneo de dos o más cargos públicos, salvo la docencia y las excepciones que determine la ley. Ningún funcionario o agente público puede representar, gestionar, patrocinar o mantener intereses privados contrarios a los del Estado Provincial o de los municipios, bajo sanción de exoneración.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 59, segments: [], amendments: [] },
  { id: 'const-salta-art-63', lawId: 'const-salta', number: '63', title: '', text: `Los agentes públicos y los funcionarios políticos deben presentar declaración jurada de su patrimonio al iniciar y concluir su gestión. No puede dictarse norma alguna que tenga por objeto acordar remuneración extraordinaria a ningún miembro de los poderes públicos por servicios prestados o que se le encomienden en el ejercicio de su función.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 60, segments: [], amendments: [] },
  { id: 'const-salta-art-64', lawId: 'const-salta', number: '64', title: '', text: `La carrera administrativa constituye un derecho de los agentes públicos de todos los poderes y organismos provinciales y municipales. La ley organiza la carrera administrativa sobre las siguientes bases: 1) Determina la jerarquía hasta la cual se extiende la carrera administrativa. 2) El ingreso se produce mediante sistemas objetivos de selección. El ascenso se funda en el mérito del agente. 3) El agente de carrera goza de estabilidad. 4) Corresponde igual remuneración por igual función. 5) El agente tiene derecho a la permanente capacitación. 6) Los agentes de la administración pública participan a través de sus representantes, en los órganos colegiados de administración de los entes descentralizados, de acuerdo a los términos de las pertinentes leyes. La ley asigna la partida presupuestaria destinada a los cargos políticos. El personal comprendido en el párrafo anterior no goza de estabilidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 61, segments: [], amendments: [] },
  { id: 'const-salta-art-65', lawId: 'const-salta', number: '65', title: '', text: `Se garantiza a los agentes públicos el derecho de agremiarse libremente en sindicatos, que pueden: 1) Concertar convenios colectivos de trabajo. 2) Recurrir a la conciliación y al arbitraje. 3) Ejercer el derecho de huelga, conforme a la reglamentación, que asegure el mantenimiento de los servicios públicos esenciales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 62, segments: [], amendments: [] },
  { id: 'const-salta-art-66', lawId: 'const-salta', number: '66', title: '', text: `El Estado Provincial provee a los gastos públicos con los fondos del tesoro constituido, conforme a las leyes, con recursos provenientes de: 1) Los tributos. 2) La renta y el producido de la venta de sus bienes. 3) La actividad económica del Estado. 4) Los derechos, participaciones, contribuciones o cánones, derivados de la explotación de sustancias minerales o del uso de bienes de dominio público. 5) Los empréstitos y demás operaciones de crédito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 63, segments: [], amendments: [] },
  { id: 'const-salta-art-67', lawId: 'const-salta', number: '67', title: '', text: `La legalidad, igualdad, equidad, proporcionalidad, progresividad, simplicidad y no confiscatoriedad son la base de los impuestos y las cargas públicas. El mayor valor de los bienes, que fuere consecuencia de obras públicas, es el hecho imponible de la contribución de mejoras, en los términos de la legislación respectiva. Las tasas retributivas de servicios exigen su efectiva prestación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 64, segments: [], amendments: [] },
  { id: 'const-salta-art-68', lawId: 'const-salta', number: '68', title: 'Presupuesto', text: `El presupuesto autoriza la realización de todos los gastos e inversiones anuales del Estado Provincial y prevé los pertinentes recursos. Su iniciativa legislativa corresponde al Poder Ejecutivo, el que puede además proponer presupuestos plurianuales sin que, en ningún caso, éstos puedan exceder el período de la gestión del titular del Poder Ejecutivo o su reemplazante legal. El presupuesto no contiene disposiciones creadoras, derogatorias o modificatorias de otras normas. El presupuesto es remitido a la Legislatura con el pertinente Plan de Obras Públicas. Toda ley u ordenanza que disponga o autorice gastos debe indicar la fuente de su financiamiento. Tales gastos y recursos deben incluirse en la primera ley de presupuesto que se apruebe, bajo sanción de caducidad. El tratamiento institucional del gasto e inversión pública se orienta hacia las siguientes prioridades indicativas: * Educación y Cultura. * Salud Pública y Seguridad Social. * Poderes del Estado y sus órganos. * Obras Públicas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 65, segments: [], amendments: [] },
  { id: 'const-salta-art-69', lawId: 'const-salta', number: '69', title: '', text: `La Legislatura puede autorizar empréstitos sobre el crédito general de la Provincia o emisión de fondos públicos. La ley que lo autorice debe ser sancionada por los dos tercios de votos de los miembros presentes de cada Cámara, actuando como originaria la de Diputados. Toda ley que sancione empréstitos especifica los recursos especiales con que deben atenderse los servicios de la deuda y su amortización, así como los objetos a que se destina el monto del empréstito. Las sumas que se obtengan por empréstitos no pueden aplicarse a otros objetos que los especificados en la ley que los autorice. La totalidad de los servicios de intereses y amortización no puede exceder la cuarta parte de los recursos ordinarios del Tesoro Provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 66, segments: [], amendments: [] },
  { id: 'const-salta-art-70', lawId: 'const-salta', number: '70', title: '', text: `El equilibrio presupuestario en el sector público provincial y municipal constituye un beneficio a favor de los habitantes de la Provincia. La Legislatura de la Provincia sanciona por los dos tercios de votos de la totalidad de los miembros de cada Cámara, una Ley de Disciplina Fiscal. Tal ley especial deberá establecer las normas para el dictado de los presupuestos anuales o plurianuales equilibrados, los niveles máximos autorizados de endeudamiento público y de gastos, en relación a los ingresos ordinarios. Dispondrá, además, que las cuentas públicas y estados financieros sean auditados. Toda modificación total o parcial de la ley, requiere para su sanción, de la mayoría calificada indicada en el segundo párrafo de este artículo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 67, segments: [], amendments: [] },
  { id: 'const-salta-art-71', lawId: 'const-salta', number: '71', title: 'Actividad Economica', text: `DISTRIBUCION DE LA RIQUEZA. La actividad económica se orienta al servicio del hombre y al progreso de la comunidad. La iniciativa económica privada es libre. Los poderes públicos promueven la distribución equitativa de la riqueza, alientan la libre competencia y sancionan la concentración monopólica, la usura y la especulación abusiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 68, segments: [], amendments: [] },
  { id: 'const-salta-art-72', lawId: 'const-salta', number: '72', title: '', text: `Los poderes públicos estimulan, con incentivos adecuados, a las empresas privadas que hagan partícipe al trabajador en sus ganancias, control de su producción y colaboración en su dirección.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 69, segments: [], amendments: [] },
  { id: 'const-salta-art-73', lawId: 'const-salta', number: '73', title: 'Cooperativas', text: `Los poderes públicos reconocen la función económica y social de las cooperativas y alientan su formación y desarrollo. Las cooperativas que colaboren con los fines del Estado en el desarrollo económico de la Provincia gozan de especial apoyo oficial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 70, segments: [], amendments: [] },
  { id: 'const-salta-art-74', lawId: 'const-salta', number: '74', title: '', text: `Las asociaciones gremiales empresarias contribuyen a la defensa y promoción de los intereses económicos y sociales que le son propios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 71, segments: [], amendments: [] },
  { id: 'const-salta-art-75', lawId: 'const-salta', number: '75', title: '', text: `EXPROPIACION. La propiedad privada es inviolable y nadie puede ser privado de ella sino en virtud de sentencia fundada en ley. El ejercicio del derecho de propiedad encuentra sus limitaciones en la función social que debe cumplir. La confiscación de bienes está abolida para siempre. La expropiación por causa de utilidad pública debe ser calificada por ley y previamente indemnizada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 72, segments: [], amendments: [] },
  { id: 'const-salta-art-76', lawId: 'const-salta', number: '76', title: '', text: `Los poderes públicos: * Realizan una política orientada al pleno empleo. * Fomentan la producción agraria y su desarrollo tecnológico. * Estabilizan la población rural y procuran su acceso a la propiedad. * Estimulan la industrialización de la Provincia promoviendo, preferentemente, la transformación de las materias primas en el ámbito de aquélla y la radicación de capitales y tecnología. * Promueven la obtención de nuevos mercados nacionales o internacionales, para los productos locales. * Elaboran planes de colonización de tierras en función de su mayor aprovechamiento económico y social.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 73, segments: [], amendments: [] },
  { id: 'const-salta-art-77', lawId: 'const-salta', number: '77', title: '', text: `CONSULTA A LOS SECTORES INTERESADOS. Los poderes públicos, en consulta con los sectores productivos y del trabajo interesados, sancionan planes económico-sociales indicativos para el sector privado de la economía e imperativos para el sector público provincial y municipal. Dichos planes procuran el desarrollo equilibrado y armonioso de la Provincia, conjugando los intereses de sus diversas regiones con los de las provincias del noroeste argentino y de la Nación. Por ley se crea el Consejo Económico Social integrado por representantes de la producción, el trabajo, la cultura, la ciencia y la tecnología. Dicho Consejo es órgano de consulta de los poderes públicos. Es obligatorio consultarlo previamente en el caso de planes económico-sociales, culturales, científicos y tecnológicos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 74, segments: [], amendments: [] },
  { id: 'const-salta-art-78', lawId: 'const-salta', number: '78', title: '', text: `Es obligación de los poderes públicos velar por la orientación del crédito hacia tareas productivas, impidiendo la especulación. Ello dentro del marco de las competencias provinciales y sin perjuicio de las nacionales en materia de moneda y crédito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 75, segments: [], amendments: [] },
  { id: 'const-salta-art-79', lawId: 'const-salta', number: '79', title: '', text: `Los servicios públicos corresponden originariamente a la Provincia o a los municipios. Se prestan en forma directa, por medio de concesión o a través de órganos constituidos por el Estado, los agentes afectados a la prestación y los usuarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 76, segments: [], amendments: [] },
  { id: 'const-salta-art-80', lawId: 'const-salta', number: '80', title: '', text: `Es obligación del Estado y de toda persona, proteger los procesos ecológicos esenciales y los sistemas de vida, de los que dependen el desarrollo y la supervivencia humana. Los poderes públicos sancionan una ley general de recursos naturales que prevé los medios y estímulos para alcanzar los objetivos señalados y sanciona los actos u omisiones que los contraríen.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 77, segments: [], amendments: [] },
  { id: 'const-salta-art-81', lawId: 'const-salta', number: '81', title: '', text: `La tierra es un instrumento de producción y objeto de una explotación racional para el adecuado cumplimiento de su función social y económica. Es obligación de todos conservar y recuperar, en su caso, la capacidad productiva de ésta, y estimular el perfeccionamiento de las técnicas de laboreo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 78, segments: [], amendments: [] },
  { id: 'const-salta-art-82', lawId: 'const-salta', number: '82', title: '', text: `La Provincia promueve la exploración y explotación de los yacimientos mineros existentes en su territorio, velando por la correcta aplicación y cumplimiento de las leyes. Procura la industrialización de los minerales en su lugar de origen, favorece la radicación de empresas y atiende el mantenimiento y desarrollo de las comunicaciones y energía, en zonas mineras.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 79, segments: [], amendments: [] },
  { id: 'const-salta-art-83', lawId: 'const-salta', number: '83', title: '', text: `Las aguas de dominio público de la Provincia están destinadas a satisfacer las necesidades de consumo y producción. Los poderes públicos preservan la calidad y reglan el uso y aprovechamiento de las aguas superficiales o subterráneas que integran el dominio de la Provincia. El uso de las aguas del dominio público destinadas a las necesidades de consumo de la población es un derecho de ésta y no puede ser objeto de concesiones a favor de personas privadas. El uso de las aguas del dominio público destinadas al riego es un derecho inherente a los predios, en beneficio de los cuales se concede en la medida y condiciones determinadas por la ley y en atención a su función social y económica. Los poderes públicos estimulan la expansión de las zonas bajo riego y la constitución de consorcios de regantes. Los usuarios del agua pública tienen participación en todo lo concerniente al aprovechamiento de aquélla. La Provincia regula el aprovechamiento de los ríos interprovinciales que nacen o atraviesan su territorio, mediante leyes o tratados con las otras provincias ribereñas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 80, segments: [], amendments: [] },
  { id: 'const-salta-art-84', lawId: 'const-salta', number: '84', title: '', text: `Los poderes públicos promueven el aprovechamiento racional de los bosques, resguardan la supervivencia, conservación, mejoramiento de las especies y reposición de aquéllas de mayor interés, a través de la forestación y reforestación. Para alcanzar tales fines, los poderes públicos ejercen las facultades inherentes al poder de policía.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 81, segments: [], amendments: [] },
  { id: 'const-salta-art-85', lawId: 'const-salta', number: '85', title: '', text: `Corresponde a la Provincia el dominio originario de los recursos naturales existentes en su territorio, la que ejerce las facultades que derivan del mismo. Los poderes públicos promueven la utilización y conservación de las fuentes de energía. Una ley determina las regalías y asigna una participación extraordinaria a favor de las regiones y municipios de los cuales se extraigan los recursos. Los poderes públicos estimulan la investigación, desarrollo y aprovechamiento de fuentes de energía no convencionales. Los residuos tóxicos tienen un destino reglado por la Legislatura, en salvaguarda de la ecología y de la vida de las personas. Se prohibe el ingreso de residuos radioactivos en todo el territorio de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 82, segments: [], amendments: [] },
  { id: 'const-salta-art-86', lawId: 'const-salta', number: '86', title: '', text: `La Constitución de la Nación, las leyes nacionales y esta Constitución, son ley suprema de la Provincia. Los poderes públicos y los habitantes están obligados a conformarse a ella, no obstante cualquier disposición en contrario que contengan las leyes o los reglamentos. El ejercicio de los derechos subjetivos y de las garantías específicas, reconocidos o declarados en esta Constitución a favor de las personas físicas o jurídicas o de un grupo de ellas, se asegura también mediante las garantías genéricas del amparo, hábeas corpus y la protección de los intereses difusos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 83, segments: [], amendments: [] },
  { id: 'const-salta-art-87', lawId: 'const-salta', number: '87', title: 'Amparo', text: `La acción de amparo procede frente a cualquier decisión, acto u omisión arbitrarios o ilegales de la autoridad, excepto la judicial, o de particulares, restrictivos o negatorios de las garantías y derechos subjetivos explícitos o implícitos de esta Constitución, tanto en el caso de una amenaza inminente cuanto en el de una lesión consumada, a los fines del cese de la amenaza o del efecto consumado. Todo Juez Letrado es competente para entender en la acción, aún en el caso que integrare un tribunal colegiado. La acción de amparo nace de esta Constitución y su procedencia no queda sujeta a las leyes que regulen las competencias de los jueces. El Juez de amparo escucha a la autoridad o particular de quien provenga la amenaza o la restricción en un plazo breve y perentorio, pudiendo habilitar al efecto horas y días inhábiles. Producida la prueba, si correspondiera, la sentencia se dictará en un plazo máximo de cinco días y podrá ser recurrida dentro de tres días. Los recursos nunca suspenden la ejecución de la sentencia cuando la misma acoge la pretensión del amparado. La acción se interpone a través de formas fehacientes, sean cuales fueren éstas. Salvo en el caso de hechos de inusitada excepcionalidad quedan prohibidas la recusación y excusación de los jueces. En estos casos se remitirán los autos que admitan aquéllas al Ministerio Público para que éste decida si dan lugar a la promoción del procedimiento de remoción del Juez. La no prestación injustificada por parte del Estado de los servicios educativos, de salud y de otros esenciales da lugar a esta acción. Todas las contingencias procesales no previstas en este artículo son resueltas por el Juez del amparo con arreglo a una recta interpretación de esta Constitución. El Juez puede declarar la inconstitucionalidadde la norma en la que se funda el acto u omisión lesiva. Son nulas y sin valor alguno las normas de cualquier naturaleza que reglamenten la procedencia y requisitos de esta acción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 84, segments: [], amendments: [] },
  { id: 'const-salta-art-88', lawId: 'const-salta', number: '88', title: '', text: `El hábeas corpus procede frente a actos, decisiones u omisiones de la autoridad o particulares que amenacen o restrinjan indebidamente la libertad ambulatoria del individuo. Procede además cuando mediare agravamiento ilegítimo de las condiciones de privación de la libertad. El hábeas corpus se puede interponer de cualquier forma y los jueces deben declarar su admisibilidad de oficio. La procedencia del hábeas corpus implica el inmediato cese de la amenaza, de las restricciones de la libertad ambulatoria o del agravamiento ilegítimo de las condiciones de una detención. Son aplicables las mismas disposiciones previstas para la acción de amparo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 85, segments: [], amendments: [] },
  { id: 'const-salta-art-89', lawId: 'const-salta', number: '89', title: '', text: `Toda persona podrá interponer acción expedita de hábeas data para tomar conocimiento de los datos referidos a ella o a sus bienes, y de su finalidad, que consten en registros o bancos de datos públicos, o los privados destinados a proveer informes. En caso de datos falsos, erróneos, obsoletos o de carácter discriminatorio, podrá exigir la supresión, rectificación, confidencialidad o actualización de aquellos. No podrá afectarse el secreto de las fuentes de información periodística.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 86, segments: [], amendments: [] },
  { id: 'const-salta-art-90', lawId: 'const-salta', number: '90', title: '', text: `Cualquier persona puede deducir la acción de amparo o interponer el hábeas corpus en el interés de un tercero sin que sea exigible la acreditación de representación de ningún tipo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 87, segments: [], amendments: [] },
  { id: 'const-salta-art-91', lawId: 'const-salta', number: '91', title: '', text: `La ley reglamenta la legitimación procesal de la persona o grupos de personas para la defensa jurisdiccional de los intereses difusos. Cualquier persona puede dirigirse también a la autoridad administrativa competente, requiriendo su intervención, en caso de que los mismos fueren vulnerados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 88, segments: [], amendments: [] },
  { id: 'const-salta-art-92', lawId: 'const-salta', number: '92', title: '', text: `Todo habitante puede interponer la acción popular directa para que se declare la inconstitucionalidadde una norma de alcance general contraria a la Constitución. Los firmantes de una demanda manifiestamente improcedente son sancionados de acuerdo a la ley. SEGUNDA`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 89, segments: [], amendments: [] },
  { id: 'const-salta-art-93', lawId: 'const-salta', number: '93', title: '', text: `FUNCIONES. La Legislatura está compuesta por una Cámara de Diputados y otra de Senadores. Ejerce el Poder Legislativo mediante leyes, controla la gestión del Poder Ejecutivo y hace efectivas las responsabilidades políticas de los altos funcionarios de la Provincia. *Art. 94.- La Cámara de Diputados se compone de representantes elegidos directamente y a simple pluralidad de sufragios por el pueblo de los distritos electorales constituidos por uno o más Departamentos, según lo fije la Ley. La Ley Electoral determina el número de diputados para cada uno de ellos. La composición de la Cámara no puede exceder de sesenta (60) miembros. Cada Departamento está representado por un (1) Diputado como mínimo. El reemplazo de los diputados que cesen en sus mandatos por muerte, renuncia o cualquier otra causa, se hace por el candidato titular que sigue en la lista y no haya resultado electo. Agotada la misma, se continúa con la de suplentes. Estos no gozan de ninguna inmunidad o derecho mientras no sean incorporados a la Cámara. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 90, segments: [], amendments: [] },
  { id: 'const-salta-art-95', lawId: 'const-salta', number: '95', title: '', text: `Las Diputadas y los Diputados duran cuatro años en sus funciones y pueden ser reelegidas o reelegidos por un solo período consecutivo. Si han sido reelectos no pueden ser elegidos, sino con el intervalo de un período. La Cámara se constituye por sí misma y se renueva por mitad cada dos años. Dicho período de cuatro años del cargo de Diputado se cuenta desde el día que se fije para la instalación de la Legislatura que le corresponda, hasta el día que precede a igual solemnidad cuatro años más tarde. El Diputado que se incorpore en reemplazo de un titular por su ausencia definitiva, completa el término del mandato del Diputado reemplazado. (*)Párrafo 1° modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 91, segments: [], amendments: [] },
  { id: 'const-salta-art-96', lawId: 'const-salta', number: '96', title: '', text: `Para ser diputado se requiere ser ciudadano y tener una residencia efectiva de cuatro años inmediatamente anteriores a su elección en el Departamento pertinente. Tener veintiún años de edad como mínimo y en su caso, el ejercicio de la nacionalidad adquirida legalmente durante cinco años.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 92, segments: [], amendments: [] },
  { id: 'const-salta-art-97', lawId: 'const-salta', number: '97', title: '', text: `Es incompatible el cargo de Diputado con : 1) El ejercicio de cualquier cargo electivo en el Gobierno Federal, Provincial, Municipal o de otras Provincias. 2) El ejercicio de una función, comisión o empleo público de la Nación, Provincias o Municipalidades, sin previo consentimiento de la Cámara. En ningún caso dicho consentimiento permite el ejercicio simultáneo del cargo de diputado con el empleo, función o comisión de que se trate. El diputado con licencia será reemplazado por el suplente inmediato, mientras dure la misma. La concesión de la licencia implica el cese de las inmunidades parlamentarias. Podrá ejercer la docencia en los términos que indique la Ley. El que incurriere en algunas de estas incompatibilidades cesa de inmediato en sus funciones de diputado. No pueden ser diputados los eclesiásticos regulares, los oficiales o suboficiales en actividad de las Fuerzas Armadas y de Seguridad, ni los excluidos del registro de electores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 93, segments: [], amendments: [] },
  { id: 'const-salta-art-98', lawId: 'const-salta', number: '98', title: '', text: `Es de competencia exclusiva de la Cámara de Diputados: 1) La iniciativa de creación de las contribuciones e impuestos generales de la Provincia y de las leyes sobre empréstitos y emisión de fondos públicos. 2) Acusar ante el Senado a los altos funcionarios y magistrados de la Provincia, que según esta Constitución quedan sometidos a juicio político por delitos en el ejercicio de sus funciones o falta de cumplimiento a los deberes a su cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 94, segments: [], amendments: [] },
  { id: 'const-salta-art-99', lawId: 'const-salta', number: '99', title: '', text: `Cuando se deduzca acusación por delitos comunes contra los funcionarios acusables por la Cámara de Diputados, no puede procederse contra su persona sin que se solicite por tribunal competente el allanamiento de la inmunidad del acusado, a cuyo efecto se remitirán los antecedentes a aquella Cámara y no podrá allanarse dicha inmunidad sino por dos tercios de votos de los miembros presentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 95, segments: [], amendments: [] },
  { id: 'const-salta-art-100', lawId: 'const-salta', number: '100', title: '', text: `REQUISITOS. El Senado se compone de tantos miembros cuantos sean los Departamentos de la Provincia, correspondiendo un senador a cada Departamento. Se elige también un senador suplente. Son requisitos para ser Senador tener treinta años de edad y reunir las demás condiciones necesarias para ser Diputado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 96, segments: [], amendments: [] },
  { id: 'const-salta-art-101', lawId: 'const-salta', number: '101', title: '', text: `El Senado presta su acuerdo a los nombramientos y remociones de los funcionarios que debe hacer el Poder Ejecutivo con este requisito. No son exigibles más acuerdos que los previstos en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 97, segments: [], amendments: [] },
  { id: 'const-salta-art-102', lawId: 'const-salta', number: '102', title: '', text: `Son también aplicables al cargo de Senador, las disposiciones establecidas en el artículo 97. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 98, segments: [], amendments: [] },
  { id: 'const-salta-art-103', lawId: 'const-salta', number: '103', title: 'Duracion', text: `Las Senadoras y los Senadores duran cuatro años en sus funciones y pueden ser reelegidas o reelegidos por un solo período consecutivo. Si han sido reelectos no pueden ser elegidos, sino con el intervalo de un período. La Cámara se constituye por sí misma y se renueva por mitad cada dos años. Dicho período de cuatro años del cargo de Senador se cuenta desde el día que se fije para la instalación de la Legislatura que le corresponda, hasta el día que precede a igual solemnidad cuatro años más tarde . El Senador que se incorpore en reemplazo de un titular por su ausencia definitiva completa el término del mandato del Senador reemplazado. (*)Párrafo 1°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 99, segments: [], amendments: [] },
  { id: 'const-salta-art-104', lawId: 'const-salta', number: '104', title: '', text: `Es atribución exclusiva del Senado juzgar en juicio político a los acusados por la Cámara de Diputados, constituyéndose al efecto en tribunal, prestando sus miembros nuevo juramento para este caso. Cuando el acusado fuere el Gobernador o Vicegobernador de la Provincia, debe presidir el Senado el Presidente de la Corte de Justicia, pero no tiene voto salvo en caso de empate.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 100, segments: [], amendments: [] },
  { id: 'const-salta-art-105', lawId: 'const-salta', number: '105', title: '', text: `En ningún caso el juicio político puede durar más de cuatro meses contados desde la fecha en que la Cámara de Diputados declare haber lugar a su formación ; puede prorrogar sus sesiones para terminarlo dentro del plazo expresado. Vencido el término mencionado sin haber recaído resolución, queda absuelto el acusado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 101, segments: [], amendments: [] },
  { id: 'const-salta-art-106', lawId: 'const-salta', number: '106', title: '', text: `El fallo del Senado, en estos casos, no tiene más efecto que destituir al acusado y aún declararlo incapaz de ocupar puestos de honor o a sueldo de la Provincia. Ningún acusado puede ser declarado culpable sin una mayoría de los dos tercios de votos de los miembros presentes. Debe votarse en estos casos nominalmente y registrarse en el acta de sesiones el voto de cada Senador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 102, segments: [], amendments: [] },
  { id: 'const-salta-art-107', lawId: 'const-salta', number: '107', title: '', text: `El que sea condenado en esta forma queda, sin embargo, sujeto a acusación, juicio y castigo por ante los tribunales ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 103, segments: [], amendments: [] },
  { id: 'const-salta-art-108', lawId: 'const-salta', number: '108', title: '', text: `El Vicegobernador de la Provincia es el Presidente del Senado, con voz pero sin voto, salvo en caso de empate.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 104, segments: [], amendments: [] },
  { id: 'const-salta-art-109', lawId: 'const-salta', number: '109', title: '', text: `El Senado designa sus vicepresidentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 105, segments: [], amendments: [] },
  { id: 'const-salta-art-110', lawId: 'const-salta', number: '110', title: 'Tiempo de las Elecciones', text: `Los Diputados y Senadores son elegidos simultáneamente con el gobernador y vicegobernador, salvo cuando sólo haya renovación parcial de las Cámaras. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 106, segments: [], amendments: [] },
  { id: 'const-salta-art-111', lawId: 'const-salta', number: '111', title: '', text: `Las Cámaras abren sus sesiones ordinarias por sí mismas el 1° de marzo de cada año y las cierran el 31 de diciembre. Funcionan en la Capital pero pueden hacerlo por causas graves o de interés público en otro sitio del territorio de la Provincia, previa resolución de ambas Cámaras. Las sesiones ordinarias pueden prorrogarse por resoluciones concordes de ambas Cámaras, adoptadas antes de fenecer el período. (*)Modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 107, segments: [], amendments: [] },
  { id: 'const-salta-art-112', lawId: 'const-salta', number: '112', title: '', text: `El Poder Ejecutivo puede convocar a las Cámaras extraordinariamente siempre que el interés público lo reclame. Son también convocadas cuando así lo pidiere, con solicitud escrita y motivada, la tercera parte de los miembros de una de las Cámaras. El pedido se presenta al Poder Ejecutivo, quien hace la convocatoria y da a publicidad la solicitud. Si éste no convoca, y un tercio de la otra Cámara pidiere también la convocatoria, la harán los presidentes. En estas sesiones sólo se tratan los asuntos que motivan la convocatoria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 108, segments: [], amendments: [] },
  { id: 'const-salta-art-113', lawId: 'const-salta', number: '113', title: '', text: `Para funcionar se necesita una mayoría absoluta, pero un número menor puede reunirse al sólo efecto de acordar las medidas que estime necesarias para compeler a los inasistentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 109, segments: [], amendments: [] },
  { id: 'const-salta-art-114', lawId: 'const-salta', number: '114', title: 'Suspension de Sesiones', text: `Ninguna de las Cámaras puede suspender sus sesiones por más de tres días sin acuerdo de la otra.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 110, segments: [], amendments: [] },
  { id: 'const-salta-art-115', lawId: 'const-salta', number: '115', title: 'Facultades de Investigacion', text: `Es atribución de cada Cámara constituir comisiones para investigar cualquier dependencia centralizada, descentralizada, empresas públicas, sociedades del Estado o en las que participe la Provincia, a los fines del ejercicio de sus propias atribuciones. También puede investigar actividades que comprometan el interés general. En su actividad no pueden interferir el ejercicio de las atribuciones que integran la zona de reserva de los otros poderes, ni afectar los derechos y garantías consagrados en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 111, segments: [], amendments: [] },
  { id: 'const-salta-art-116', lawId: 'const-salta', number: '116', title: '', text: `Los Ministros del Poder Ejecutivo están facultados para asistir a las sesiones de cada Cámara, con voz pero sin voto. Pueden ser acompañados por los Secretarios de Estado dependientes de su Ministerio o por la máxima autoridad de los entes descentralizados, quienes asisten con voz pero sin voto. Los Ministros, Secretarios de Estado y las máximas autoridades de los entes descentralizados deben comparecer ante la Cámara o sus comisiones, cuando son citados a fin de suministrar informes. Corresponde a toda la administración centralizada, descentralizada o sociedades en las que participe la Provincia, responder por escrito los requerimientos de informes de cada Cámara o de sus comisiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 112, segments: [], amendments: [] },
  { id: 'const-salta-art-117', lawId: 'const-salta', number: '117', title: '', text: `MESA DIRECTIVA. Cada Cámara dicta y se rige por un reglamento especial y nombra su mesa directiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 113, segments: [], amendments: [] },
  { id: 'const-salta-art-118', lawId: 'const-salta', number: '118', title: '', text: `EMPLEADOS. Forman también su presupuesto, el que debe considerarse por la Legislatura conjuntamente con el presupuesto general, y establecen la forma de nombramiento de sus empleados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 114, segments: [], amendments: [] },
  { id: 'const-salta-art-119', lawId: 'const-salta', number: '119', title: '', text: `Las sesiones de ambas Cámaras son públicas y sólo pueden hacerse secretas por asuntos graves y acuerdo de la mayoría.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 115, segments: [], amendments: [] },
  { id: 'const-salta-art-120', lawId: 'const-salta', number: '120', title: 'Inmunidad de Opinion', text: `Los miembros de ambas Cámaras son inviolables por las opiniones que manifiesten y votos que emitan en el desempeño de su cargo. No hay autoridad alguna que pueda procesarlos ni reconvenirlos en ningún tiempo por tales causas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 116, segments: [], amendments: [] },
  { id: 'const-salta-art-121', lawId: 'const-salta', number: '121', title: '', text: `Los Diputados y Senadores gozan de inmunidad en su persona desde el día de su elección hasta el cese de su mandato y no pueden ser arrestados por ninguna autoridad sino en el caso de ser sorprendidos en flagrante delito pasible de pena corporal, dándose inmediata cuenta a la Cámara respectiva con la información sumaria del hecho, para que resuelva lo que corresponda, según el caso, sobre la inmunidad personal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 117, segments: [], amendments: [] },
  { id: 'const-salta-art-122', lawId: 'const-salta', number: '122', title: 'Desafuero', text: `Cuando se deduzca acusación ante la justicia ordinaria contra un Senador o Diputado, examinado el mérito del sumario en juicio público, puede cada Cámara con dos tercios de votos de los miembros presentes, suspender en sus funciones al acusado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 118, segments: [], amendments: [] },
  { id: 'const-salta-art-123', lawId: 'const-salta', number: '123', title: '', text: `Cada Cámara puede corregir a cualquiera de sus miembros por desorden de conducta en el ejercicio de sus funciones y hasta excluirlo de su seno por razones de incapacidad física o moral sobreviniente, debiendo para tal efecto, concurrir los dos tercios de votos de los miembros presentes ; pero basta la mayoría de uno sobre la mitad de los presentes para decidir en las renuncias que voluntariamente hicieren de su cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 119, segments: [], amendments: [] },
  { id: 'const-salta-art-124', lawId: 'const-salta', number: '124', title: 'Juramento', text: `En el acto de su incorporación los Senadores y Diputados prestan juramento de desempeñar debidamente el cargo y de obrar en todo de acuerdo a lo que prescribe esta Constitución y la de la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 120, segments: [], amendments: [] },
  { id: 'const-salta-art-125', lawId: 'const-salta', number: '125', title: '', text: `No pueden ser elegidos legisladores los condenados por sentencia, mientras dure la condena y la mitad más del tiempo de su duración; los fallidos no rehabilitados ; los afectados de incapacidad física o moral; ni los deudores morosos del fisco provincial, después de sentencia judicial que los condene.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 121, segments: [], amendments: [] },
  { id: 'const-salta-art-126', lawId: 'const-salta', number: '126', title: '', text: `Cada Cámara tiene autoridad para corregir, con arresto que no pase de un mes, a toda persona de fuera de su seno que viole sus privilegios, con arreglo a los principios parlamentarios; pudiendo, cuando a su juicio el caso fuera grave y lo hallase conveniente, ordenar que el inculpado sea sometido a los tribunales ordinarios para su enjuiciamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 122, segments: [], amendments: [] },
  { id: 'const-salta-art-127', lawId: 'const-salta', number: '127', title: '', text: `Corresponde al Poder Legislativo: 1) Sancionar las leyes reglamentarias de los Derechos, Deberes y Garantías consagrados por esta Constitución. 2) Sancionar la Ley de Presupuesto General. Si el Poder Ejecutivo no remitiere los proyectos de presupuesto y leyes de recursos para el ejercicio siguiente antes del 31 de agosto, la Legislatura puede iniciar su estudio y sancionarlos, tomando como base las leyes vigentes. Vencido el ejercicio administrativo sin que la Legislatura sancione una nueva ley de Gastos y Recursos, se tienen por prorrogadas las que hasta ese momento se encuentren en vigor. La Ley de Presupuesto debe comprender la totalidad de los recursos y erogaciones de la hacienda central, hacienda descentralizada y haciendas paraestatales y fijar el número de cargos de la planta de personal permanente y transitorio. El presupuesto a aprobar por la Legislatura refleja analíticamente los ingresos y gastos. No pueden las Cámaras pasar a receso sin haber aprobado el presupuesto y sin haber considerado la Cuenta General del Ejercicio. 3) Aprobar, observar o desechar anualmente la Cuenta General del Ejercicio que le remita el Poder Ejecutivo antes del 30 de junio, correspondiente al movimiento de la totalidad de la hacienda pública provincial realizado durante el año anterior. 4) Disponer la descentralización de servicios de la Administración Provincial y la constitución de empresas públicas y sociedades del Estado. 5) Facultar al Poder Ejecutivo para contraer empréstitos u operaciones de créditos y acordar aportes no reintegrables a las municipalidades. 6) Reglamentar y autorizar los juegos de azar y destreza. 7) Aprobar o desechar los tratados suscriptos por la Provincia con otras Provincias, la Nación, Municipios de otros Estados, Organismos Internacionales o Estados Extranjeros, como también los que tengan por finalidad constituir regiones sustentadas en afinidades e intereses comunes y establecer órganos para el cumplimiento de sus fines, de conformidad con la Constitución Nacional y disposiciones de esta Constitución. Asimismo podrá autorizar a que el Poder Ejecutivo realice aquellos convenios que no impongan obligaciones significativas a la Provincia. 8) Fijar las divisiones territoriales de la Provincia. 9) Conceder amnistías generales. 10) Autorizar las medidas de defensa en los casos en que la seguridad pública de la Provincia lo exija. 11) Establecer los impuestos y contribuciones para los gastos del servicio público. 12) Legislar sobre tierras públicas de la Provincia, debiendo dictarse una ley general sobre la materia. 13) Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles y administrativas de los funcionarios y empleados públicos provinciales y municipales. 14) Conceder exenciones por un tiempo limitado a los autores o inventores y primeros introductores de nuevas industrias para explotar en la Provincia, sin perjuicio de las atribuciones del Gobierno Federal. 15) Crear y reglamentar facultativamente la organización y funcionamiento de un cargo de Comisionado Legislativo, que tendrá como función peticionar ante la administración en interés de los habitantes de la Provincia, en representación del Poder Legislativo. 16) Sancionar las otras leyes previstas en la Constitución y las que se relacionen con todo interés público general de la Provincia, que, por su naturaleza y objeto no correspondan a la Nación o que no fueren atribuciones propias de los otros poderes del Estado Provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 123, segments: [], amendments: [] },
  { id: 'const-salta-art-128', lawId: 'const-salta', number: '128', title: '', text: `Toda ley puede tener principio en cualquiera de las Cámaras, excepto aquéllas cuya iniciativa se confiere privativamente a la de Diputados. Se propone en forma de proyecto por cualquiera de los miembros de cada Cámara y también por el Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 124, segments: [], amendments: [] },
  { id: 'const-salta-art-129', lawId: 'const-salta', number: '129', title: '', text: `Aprobado un proyecto por la Cámara de su origen, pasa para su revisión a la otra, y si ésta también lo aprobase, se comunica al Poder Ejecutivo para su promulgación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 125, segments: [], amendments: [] },
  { id: 'const-salta-art-130', lawId: 'const-salta', number: '130', title: '', text: `Ningún proyecto de ley desechado totalmente por una de las Cámaras puede repetirse en las sesiones del mismo año. Pero si sólo es adicionado o corregido por la Cámara revisora, vuelve a la de su origen, y si en ésta se aprobasen las adiciones o correcciones por mayoría absoluta, pasa al Poder Ejecutivo. Si las adiciones o correcciones son desechadas, vuelve por segunda vez el proyecto a la Cámara revisora; y si aquí fuesen sancionadas nuevamente por una mayoría de dos terceras partes de sus miembros presentes, pasa el proyecto a la otra Cámara, y no se entiende que ésta reprueba dichas adiciones o correcciones si no concurre para ello el voto de las dos terceras partes de sus miembros presentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 126, segments: [], amendments: [] },
  { id: 'const-salta-art-131', lawId: 'const-salta', number: '131', title: '', text: `El Poder Ejecutivo debe promulgar los proyectos de ley sancionados dentro de los diez días hábiles de haberle sido remitidos por la Legislatura ; pero puede devolverlos con observaciones durante dicho plazo, y si una vez transcurrido no ha hecho la promulgación, ni los ha devuelto con objeciones, son ley de la Provincia, debiendo promulgarse en el día por el Poder Ejecutivo. Observado en parte el proyecto de ley por el Poder Ejecutivo, éste sólo puede promulgar la parte no observada si ella tiene autonomía normativa y no afecta la unidad y el sentido del proyecto. Respecto de la parte observada se sigue el procedimiento previsto en el artículo 133, teniendo cada Cámara un plazo perentorio de cuarenta y cinco días para su tratamiento en sesiones ordinarias, o convocando de inmediato a sesiones extraordinarias con igual plazo si estuviere en receso. Transcurrido dicho plazo sin haber sido tratada, la parte observada queda definitivamente desechada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 127, segments: [], amendments: [] },
  { id: 'const-salta-art-132', lawId: 'const-salta', number: '132', title: '', text: `VETO. Si antes del vencimiento de los diez días tiene lugar la clausura de las sesiones de las Cámaras, el Poder Ejecutivo debe, dentro de dicho término, devolver el proyecto vetado a la secretaría de la Cámara que lo haya remitido, sin cuyo requisito no tiene efecto el veto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 128, segments: [], amendments: [] },
  { id: 'const-salta-art-133', lawId: 'const-salta', number: '133', title: '', text: `Devuelto un proyecto por el Poder Ejecutivo, es considerado primero por la Cámara de origen, pasando luego a la revisora, y si ambas insisten en la sanción por el voto de los dos tercios de sus miembros presentes, el proyecto es ley y el Poder Ejecutivo está obligado a promulgarla. En caso contrario no puede repetirse en las sesiones del mismo año. Si se aceptan por mayoría en ambas Cámaras las modificaciones introducidas por el Poder Ejecutivo, el proyecto queda convertido en ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 129, segments: [], amendments: [] },
  { id: 'const-salta-art-134', lawId: 'const-salta', number: '134', title: '', text: `PROMULGACION. Si un proyecto de ley observado vuelve a ser sancionado en uno de los dos períodos subsiguientes, el Poder Ejecutivo no puede observarlo de nuevo y está obligado a promulgarlo como ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 130, segments: [], amendments: [] },
  { id: 'const-salta-art-135', lawId: 'const-salta', number: '135', title: '', text: `Cuando se hace la publicación oficial de las leyes de la Provincia, se enumeran ordinalmente y en adelante se tiene la numeración correlativa por la fecha de la promulgación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 131, segments: [], amendments: [] },
  { id: 'const-salta-art-136', lawId: 'const-salta', number: '136', title: '', text: `En la sanción de las leyes se usa la siguiente forma: "El Senado y la Cámara de Diputados de la Provincia, sancionan con fuerza de ley".`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 132, segments: [], amendments: [] },
  { id: 'const-salta-art-137', lawId: 'const-salta', number: '137', title: '', text: `Ambas Cámaras sólo se reúnen para el desempeño de las funciones siguientes: 1) La apertura a las sesiones ordinarias. 2) Recibir el juramento de ley al Gobernador y Vicegobernador de la Provincia. 3) Admitir o desechar la renuncia que de su cargo hiciere el Gobernador o Vicegobernador de la Provincia. 4)Suprimido. (*)Inc. 4: suprimido por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 133, segments: [], amendments: [] },
  { id: 'const-salta-art-138', lawId: 'const-salta', number: '138', title: '', text: `Las reuniones de la Asamblea General son presididas por el Vicegobernador. En su defecto subsidiariamente por el vicepresidente del Senado, el presidente de la Cámara de Diputados o el senador de mayor edad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 134, segments: [], amendments: [] },
  { id: 'const-salta-art-139', lawId: 'const-salta', number: '139', title: 'Quorum', text: `No puede funcionar la Asamblea sin la mayoría absoluta de los miembros de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 135, segments: [], amendments: [] },
  { id: 'const-salta-art-140', lawId: 'const-salta', number: '140', title: 'Gobernador y Vicegobernador', text: `El Poder Ejecutivo de la Provincia es desempeñado por un ciudadano con el título de Gobernador de la Provincia. Al mismo tiempo y por el mismo período se nombra a un Vicegobernador de la Provincia. El Gobernador formula y dirige las políticas de la Provincia y representa a la misma. Es el Jefe de la administración centralizada y descentralizada. Duran cuatro años en el ejercicio de sus funciones y pueden ser reelegidos o sucederse recíprocamente en los citados cargos por un solo período consecutivo. Si han sido reelectos o se han sucedido recíprocamente, no pueden ser elegidos para ninguno de ambos cargos, sino con el intervalo de un período. No pueden ser elegidos, por un período inmediato al cese del cargo de la Gobernadora o Gobernador y de la Vicegobernadora o el Vicegobernador, sus parientes hasta el segundo grado, su cónyuge o con quien tenga unión convivencial. Cesan en sus funciones el mismo día en que expira el período legal sin que por ninguna causa pueda prorrogarse ni completarse. (*)Párrafo 4°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021). Fe de Erratas por B.O. 22/12/201`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 136, segments: [], amendments: [] },
  { id: 'const-salta-art-141', lawId: 'const-salta', number: '141', title: '', text: `Para ser Gobernador o Vicegobernador se requiere: 1) Ser argentino nativo o por opción. 2) Tener por lo menos 30 años de edad y ser elector. 3) Haber residido en la Provincia durante los cuatro años anteriores inmediatos a la elección, y durante cinco el ciudadano por opción, salvo que la ausencia haya sido causada por servicios públicos a la Nación o a la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 137, segments: [], amendments: [] },
  { id: 'const-salta-art-142', lawId: 'const-salta', number: '142', title: '', text: `El Gobernador y Vicegobernador son elegidos por el voto directo del pueblo y a simple mayoría de sufragios. Con una antelación mínima de seis meses a la conclusión del período gubernativo, el Poder Ejecutivo convoca a elecciones de gobernador y vicegobernador. Practicado el escrutinio general y el de las elecciones complementarias en su caso, el Tribunal Electoral proclama en acto público gobernador y vicegobernador a los ciudadanos electos, comunicándoles inmediatamente ese resultado a fin que manifiesten su aceptación en el término de tres días. En caso de empate la Asamblea Legislativa resuelve, cumpliendo su cometido en una sola sesión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 138, segments: [], amendments: [] },
  { id: 'const-salta-art-143', lawId: 'const-salta', number: '143', title: '', text: `AUSENCIA DE LA CAPITAL. INMUNIDADES. JURAMENTO. El gobernador y vicegobernador gozan de la remuneración prevista por la ley y durante su desempeño no pueden ejercer otro empleo ni recibir otro emolumento de la Nación, de la Provincia o Municipios. Gozan desde el momento de su elección hasta el término de sus funciones de las mismas inmunidades que los legisladores. El Gobernador no puede ausentarse de la capital ni del territorio de la Provincia por más de treinta días corridos, sin permiso de la Legislatura. El gobernador y vicegobernador juran ante la Asamblea Legislativa. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 139, segments: [], amendments: [] },
  { id: 'const-salta-art-144', lawId: 'const-salta', number: '144', title: '', text: `El Gobernador, o su reemplazante legal, tiene las siguientes atribuciones y deberes: 1) Representa a la Provincia en todas sus relaciones oficiales. 2) Ejerce la potestad de dirigir toda la administración provincial. 3) Ejerce la potestad reglamentaria. En la reglamentación de las leyes no puede alterar su espíritu. 4) Participa en la formación de las leyes con arreglo a esta Constitución, iniciándolas, tomando intervención en su discusión por intermedio de los ministros y promulgándolas o vetándolas total o parcialmente. 5) Indulta y conmuta penas, previo informe de la Corte Justicia sobre su conveniencia y oportunidad. No ejerce esta facultad respecto de los funcionarios públicos condenados por delitos cometidos en el ejercicio de sus funciones y de los funcionarios destituidos por juicio político. 6) Informa a las Cámaras reunidas en Asamblea Legislativa, el 1° de marzo de cada año, sobre el estado general de la Provincia. 7) Nombra y remueve por sí solo a los ministros, funcionarios y agentes de la Administración con sujeción a esta Constitución y a las leyes; y con acuerdo del Senado, en los casos previstos por aquélla. 8) Presenta a la Legislatura antes del 1. de agosto el Proyecto de Ley de Presupuesto. 9) Hace recaudar las rentas de la Provincia y ejecutar judicialmente su cobro. Decreta su inversión con arreglo a la ley y dispone la publicidad, periódicamente, del estado de la Tesorería. 10) Convoca a elecciones provinciales. 11) Convoca a sesiones extraordinarias a la Legislatura indicando los asuntos que determinan tal convocatoria. 12) Conviene con la Nación y demás provincias regímenes de coparticipación o multilaterales de carácter impositivo y sobre regalías, con aprobación del Poder Legislativo. 13) Celebra tratados o acuerdos para la gestión de intereses propios de la Provincia, con la Nación y las demás provincias, con aprobación del Poder Legislativo. 14) Impulsa negociaciones o entendimientos con otras naciones y organismos internacionales para la gestión de intereses de la Provincia, sin afectar la política exterior, cuya conducción es competencia del Gobierno Federal. 15) Concede pensiones con arreglo a la ley. 16) Auxilia con la fuerza a los poderes públicos. 17) Actúa como agente natural del Gobierno Federal para hacer cumplir en la Provincia la Constitución y las leyes de la Nación. 18) Adopta las medidas necesarias para conservar la paz y el orden público por todos los medios que no estén expresamente prohibidos por la Constitución y leyes vigentes. (*)Inc. 6) modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 140, segments: [], amendments: [] },
  { id: 'const-salta-art-145', lawId: 'const-salta', number: '145', title: '', text: `En caso de estado de necesidad y urgencia, o que esté amenazado de una manera grave e inminente el funcionamiento regular de los poderes públicos constitucionales, el Poder Ejecutivo, en acuerdo general de Ministros, y previa consulta oficial al Fiscal de Estado y a los Presidentes de ambas Cámaras Legislativas, puede dictar decretos sobre materias de competencia legislativa. Informa de ello a la Provincia mediante un mensaje público. En tal caso, debe remitir el decreto a la Legislatura dentro de los cinco días de dictado, convocando de inmediato a sesión extraordinaria si estuviere en receso, bajo apercibimiento de perder su eficacia en forma automática. Transcurridos noventa días desde su recepción por la Legislatura, sin haber sido aprobado o rechazado por ésta, el decreto de estado de necesidad y urgencia queda convertido en ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 141, segments: [], amendments: [] },
  { id: 'const-salta-art-146', lawId: 'const-salta', number: '146', title: '', text: `ACEFALIA. En los casos de ausencia definitiva o temporaria del Gobernador, éste es reemplazado por el Vicegobernador hasta la conclusión del período por el que fueron electos o hasta la desaparición de la causa de la ausencia temporaria. Si se produce ausencia, separación o impedimento simultáneo, temporario o definitivo del Gobernador y del Vicegobernador, el Poder Ejecutivo de la Provincia es ejercido por el vicepresidente del Senado; a falta de éste, por el presidente de la Cámara de Diputados; en defecto de ambos, por un ministro conforme al orden de prelación establecido por ley. En caso de acefalía total y definitiva, el ciudadano en ejercicio del Poder Ejecutivo convoca al pueblo de la Provincia dentro los quince días de ocurrida la vacante, dando sesenta días de término a una nueva elección para Ilenar el período corriente, siempre que de éste falte por lo menos un año. En caso de acefalía en el cargo de vicegobernador, la elección para su reemplazo debe ser convocada conjuntamente con la próxima elección de gobernador. Si el ciudadano elegido gobernador, antes de tomar posesión de su cargo, renuncia, o por cualquier impedimento no puede ocuparlo, se procede a una nueva elección. El Poder Ejecutivo debe convocar la misma dentro de los quince días de producida la vacancia, dando treinta días de término para la realización de la elección. Si antes de ese día el gobernador saliente ha cesado en su cargo, el vicegobernador electo ocupa el mismo hasta que el gobernador electo sea proclamado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 142, segments: [], amendments: [] },
  { id: 'const-salta-art-147', lawId: 'const-salta', number: '147', title: '', text: `LEY DE MINISTERIOS. El despacho de los asuntos de la Provincia está a cargo de ministros que refrendan los actos del Gobernador, sin cuyo requisito carecen de validez. Pueden, por sí solos, resolver todo lo referente al régimen interno y disciplinario de sus respectivos ministerios. Una ley, cuya iniciativa corresponde al Poder Ejecutivo, determina el número de ministros y secretarios de estado, sus competencias y atribuciones. El gobernador puede delegar en un ministro sus potestades administrativas, encomendarle la tarea de coordinación entre los distintos ministerios y la de exposición de los planes de gobierno y de su ejecución ante las Cámaras Legislativas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 143, segments: [], amendments: [] },
  { id: 'const-salta-art-148', lawId: 'const-salta', number: '148', title: '', text: `INCOMPATIBILIDADES. RESPONSABILIDAD. Los Ministros deben tener 25 años de edad y reunir las demás condiciones para ser elegidos Diputados ; tienen iguales incompatibilidades que los legisladores. Perciben la remuneración que marca la ley. Son solidariamente responsables con el Gobernador de los actos que autoricen, sin que sea admisible la excusa de una orden de éste.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 144, segments: [], amendments: [] },
  { id: 'const-salta-art-149', lawId: 'const-salta', number: '149', title: '', text: `El Fiscal de Estado es el encargado de la defensa del Patrimonio del Fisco. Es parte legítima en todos los juicios en que se afecten intereses y bienes de la Provincia. Emite dictamen sobre las cuestiones que el Gobernador de la Provincia le requiera. A requerimiento del Gobernador se encuentra legitimado para demandar la inconstitucionalidady nulidad de toda ley, decreto, ordenanza, contrato, resolución o acto de cualquier autoridad de la Provincia que sean contrarios a las prescripciones de esta Constitución. El Fiscal de Estado es nombrado por el Poder Ejecutivo con acuerdo del Senado y dura todo el período del Gobernador que lo designó o de su reemplazante legal, pudiendo ser designado nuevamente. Debe reunir las mismas condiciones que los Jueces de la Corte de Justicia y está sujeto a juicio político. Una ley orgánica regula sus funciones y competencias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 145, segments: [], amendments: [] },
  { id: 'const-salta-art-150', lawId: 'const-salta', number: '150', title: '', text: `El Poder Judicial de la Provincia es ejercido por una Corte de Justicia, que asegura el ejercicio independiente de la función judicial, compuesta por un número impar de jueces establecido por ley, y demás tribunales inferiores que la ley determine, fijándoles su jurisdicción y competencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 146, segments: [], amendments: [] },
  { id: 'const-salta-art-151', lawId: 'const-salta', number: '151', title: '', text: `El Poder Judicial, para afirmar y mantener la inviolabilidad de su independencia orgánica y funcional, tiene todo el imperio necesario.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 147, segments: [], amendments: [] },
  { id: 'const-salta-art-152', lawId: 'const-salta', number: '152', title: '', text: `SALAS. El Presidente de la Corte Justicia es elegido cada dos años entre sus miembros. Para ejercitar su competencia por vía recursiva la Corte puede dividirse en Salas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 148, segments: [], amendments: [] },
  { id: 'const-salta-art-153', lawId: 'const-salta', number: '153', title: '', text: `La Corte de Justicia, sin perjuicio de las demás que le confiere la ley conforme a sus funciones y jerarquía, tiene las siguientes atribuciones y competencias: I. Atribuciones: a) Ejerce la superintendencia de la Administración de Justicia. b) Dicta los reglamentos necesarios para el mejor desempeño de la función judicial. c) Nombra a los funcionarios o empleados del Poder Judicial conforme al articulo 64 inciso 2) de esta Constitución, y los remueve. Los Secretarios y Prosecretarios Letrados son designados previo concurso público. d) Confecciona su presupuesto de erogaciones. e) Tiene iniciativa legislativa, no exclusiva, con respecto a la ley de organización del Poder Judicial, Códigos Procesales y demás leyes referidas directamente al funcionamiento de este poder. f) Tiene voz, a través de uno de sus miembros, en las deliberaciones legislativas en las que se trate su presupuesto o alguna de las leyes referidas en el inciso anterior. g) Supervisa el sistema carcelario de la Provincia. h) Dirige la Escuela de la Magistratura con participación de los Jueces Inferiores. Es la intérprete final, en el ámbito provincial, de las constituciones de la Nación y de la Provincia. II. Le compete conocer y decidir en forma originaria: a) Las acciones sobre inconstitucionalidadde leyes, decretos, ordenanzas, reglamentos o resoluciones que estatuyan sobre materias regidas por esta Constitución. b) En los conflictos de jurisdicción y competencia entre los Poderes Públicos, provinciales y municipales, entes públicos, autoridades, entre las ramas de un mismo poder y en los que se susciten entre los Tribunales de Justicia. c) En las acciones de amparo, hábeas corpus y hábeas data contra cualquier acto u omisión de algunas de las Cámaras Legislativas o del titular del Poder Ejecutivo. III. Le compete conocer y decidir por vía recursiva: a) En los recursos contra las decisiones de última instancia de tribunales inferiores contrarias a la Constitución Nacional y a esta Constitución. b) En los demás recursos previstos especialmente por las leyes. c) En los recursos contra las decisiones definitivas de los jueces inferiores en las acciones de amparo, hábeas corpus y hábeas data.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 149, segments: [], amendments: [] },
  { id: 'const-salta-art-154', lawId: 'const-salta', number: '154', title: '', text: `Para ser juez de Corte o de Cámara, se requiere ser ciudadano argentino, poseer título de abogado y tener por lo menos treinta años de edad, diez en el ejercicio de la profesión de abogado o de la magistratura o ministerio público, y cuatro años de residencia inmediata en la Provincia si no hubiere nacido en ésta. Para los demás jueces, se requiere ser ciudadano argentino, poseer título de abogado, tener veintiséis años de edad y seis años en el ejercicio de la profesión de abogado o en la función judicial o ministerio público y cuatro años de residencia inmediata en la Provincia si no hubiere nacido en ésta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 150, segments: [], amendments: [] },
  { id: 'const-salta-art-155', lawId: 'const-salta', number: '155', title: '', text: `Los jueces y secretarios no pueden realizar actividad política partidaria. Tampoco pueden ejercer profesión, empleo ni actividad con fines de lucro, salvo la docencia, las comisiones de carácter honorario, técnicas y transitorias que les encomienden los poderes públicos nacionales, provinciales o municipales, y la defensa en juicio de derechos propios. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 151, segments: [], amendments: [] },
  { id: 'const-salta-art-156', lawId: 'const-salta', number: '156', title: '', text: `Las Juezas y los Jueces de la Corte de Justicia de Salta son nombrados por el Poder Ejecutivo, previo procedimiento participativo de la ciudadanía establecido por Ley, con acuerdo del Senado prestado en sesión pública. Duran diez años en sus funciones, no pudiendo ser nombrados nuevamente. Los demás Jueces son designados de la misma manera previa selección de postulantes por el Consejo de la Magistratura y son inamovibles en sus cargos mientras dure su buena conducta y desempeño. Las Magistradas y los Magistrados Inferiores del Poder Judicial cesan en el cargo, indefectiblemente, al obtener la jubilación o el día en que cumplan los 70 años de edad, lo que ocurra primero. La ley instrumenta y garantiza la capacitación de los miembros del Poder Judicial y la carrera judicial abierta y con igualdad de oportunidades. (*)Párrafo 1°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021) (*)Párrafo 3°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021). Fe de Erratas por B.O. 22/12/201`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 152, segments: [], amendments: [] },
  { id: 'const-salta-art-157', lawId: 'const-salta', number: '157', title: '', text: `COMPOSICION. El Consejo de la Magistratura, reglamentado por ley, tiene a su cargo la selección de los Magistrados Inferiores del Poder Judicial, Jueces de Paz Letrados y funcionarios del Ministerio Público con excepción del Procurador General, el Defensor General y el Asesor General de Incapaces, mediante concurso público, y está integrado por: a) Un Juez de la Corte de Justicia elegido por sus pares, que lo preside. b) Un representante de los Jueces inferiores, elegido entre ellos, por voto directo, secreto y obligatorio. c) Un representante del Ministerio Público, elegido entre los funcionarios del mismo, por voto directo, secreto y obligatorio. d) Tres abogados de la matrícula elegidos entre sus pares por voto directo, secreto y obligatorio, respetando las minorías. e) Tres representantes de la Cámara de Diputados, miembros o no de ella, correspondiendo dos a la mayoría y uno a la primera minoría, a propuesta de los respectivos bloques. Por cada titular se elegirá un Suplente para reemplazarlo en caso de remoción, renuncia, cese o fallecimiento. Todos sus integrantes deberán reunir los mismos requisitos que exige esta Constitución para ser Juez de la Corte de Justicia, a excepción de los representantes referidos en el inciso e).`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 153, segments: [], amendments: [] },
  { id: 'const-salta-art-158', lawId: 'const-salta', number: '158', title: '', text: `Los miembros del Consejo de la Magistratura duran cuatro años en sus funciones no pudiendo ser reelectos en forma inmediata. Cesan si se altera la condición funcional por la que fueron elegidos o por la pérdida de algunos de los requisitos exigidos o por mal desempeño de sus funciones ; en este último caso la separación la decidirá el Consejo con el voto de las dos terceras partes de la totalidad de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 154, segments: [], amendments: [] },
  { id: 'const-salta-art-159', lawId: 'const-salta', number: '159', title: '', text: `El Consejo de la Magistratura tiene las siguientes atribuciones : a) Selecciona mediante concurso público a los postulantes a las magistraturas inferiores del Poder Judicial, Jueces de Paz Letrados y funcionarios del Ministerio Público. b) Remite al Poder Ejecutivo ternas vinculantes para el nombramiento de los magistrados y funcionarios referidos en el inciso anterior. c) Dicta su Reglamento Interno. d) Convoca a elecciones para la designación de los representantes de los Jueces Inferiores, de los funcionarios del Ministerio Público y de los abogados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 155, segments: [], amendments: [] },
  { id: 'const-salta-art-160', lawId: 'const-salta', number: '160', title: '', text: `Los jueces de la Corte de Justicia están sujetos a juicio político, con idéntico procedimiento que el previsto para la remoción del Gobernador, por las causales de delito común, mala conducta, retardo de justicia, mal desempeño o falta de cumplimiento de los deberes a su cargo. La formación de causa requiere el voto de los dos tercios de los miembros presentes de la Cámara de Diputados, mayoría aplicable en todos los casos previstos en esta Constitución para la promoción de juicio político. Los demás jueces pueden ser acusados por cualquiera del pueblo o por el Ministerio Público por las mismas causales previstas para los jueces de la Corte de Justicia por ante un jurado de enjuiciamiento integrado por el Presidente de la Corte que lo preside ; un Juez de Corte elegido por sus pares ; dos diputados y dos senadores, abogados si los hubiera, uno por la mayoría y otro por la primera minoría a propuesta de los respectivos bloques de cada Cámara ; el Fiscal de Estado; un abogado de la matrícula designado por la Cámara de Diputados y un abogado de la matrícula designado por la Cámara de Senadores. Los abogados designados por ambas cámaras deberán reunir las condiciones exigidas para ser Juez de Corte. Los miembros del jurado son elegidos cada dos años pudiendo ser reelectos. Actúa como secretario el Secretario de la Corte de Justicia que ésta designe cada dos años. El jurado juzga en juicio público que debe concluir dentro de los cuatro meses contados a partir del momento de la acusación bajo sanción de caducidad. El fallo no tiene más efecto que destituir al acusado y aún declararlo inhábil para ocupar cargos en la provincia remitiéndose, en su caso, los antecedentes a la justicia ordinaria. Al declararse la admisibilidad formal y la existencia prima facie de motivos de destitución, previo a la sustanciación de juicio, el enjuiciado quedará suspendido en sus funciones. El no juzgamiento en término de los responsables, por causas imputables a miembros del tribunal, es causal de destitución e inhabilitación para ocupar cargos públicos. También es atribución del Jurado de Enjuiciamiento allanar la inmunidad de los magistrados y funcionarios del Ministerio Público cuando se formule contra ellos acusación por delitos comunes. Una ley regula todo lo atinente al funcionamiento de este tribunal, respetando, bajo sanción de nulidad, las reglas precedentemente establecidas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 156, segments: [], amendments: [] },
  { id: 'const-salta-art-161', lawId: 'const-salta', number: '161', title: '', text: `Los jueces gozan de las mismas inmunidades que los miembros del Poder Legislativo y su retribución no puede ser suspendida ni disminuida sino por leyes de carácter general, extensivas a todos los poderes del Estado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 157, segments: [], amendments: [] },
  { id: 'const-salta-art-162', lawId: 'const-salta', number: '162', title: '', text: `Una ley organiza la justicia de paz lega y letrada, teniendo en cuenta las divisiones administrativas, extensión y población de la Provincia. Fija su jurisdicción, competencia, procedimiento y requisitos para el cargo de juez. Para la Justicia de Paz Lega se procura que el procedimiento sea verbal y actuado. El juez resuelve a verdad sabida y buena fe guardada, pudiendo fundar sus resoluciones en el principio de equidad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 158, segments: [], amendments: [] },
  { id: 'const-salta-art-163', lawId: 'const-salta', number: '163', title: '', text: `NOMBRAMIENTO. REMOCION. INMUNIDADES. Los Jueces de Paz Legos son designados por la Corte de Justicia. Serán seleccionados de una terna elevada por los Intendentes Municipales, con acuerdo de los Concejos Deliberantes. Son remunerados y duran cuatro años en el ejercicio de sus funciones, pudiendo ser designados nuevamente. Gozan de las mismas inmunidades que los demás jueces y son removidos por las mismas causales que éstos, mediante acusación de cualquiera del pueblo, hecha por ante la Corte de Justicia, la que debe reglamentar el procedimiento garantizando el derecho de defensa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 159, segments: [], amendments: [] },
  { id: 'const-salta-art-164', lawId: 'const-salta', number: '164', title: '', text: `El Ministerio Público es ejercido por un Procurador General, un Defensor General y un Asesor General de Incapaces quienes tendrán a su cargo la superintendencia y las potestades administrativas y económicas del mismo en forma conjunta. El Presidente es elegido cada dos años entre sus miembros. La ley establece la competencia de los fiscales, defensores, asesores y demás funcionarios determinando su orden jerárquico, número, sede, atribuciones, responsabilidades y normas de funcionamiento.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 160, segments: [], amendments: [] },
  { id: 'const-salta-art-165', lawId: 'const-salta', number: '165', title: '', text: `DESIGNACION. INMUNIDADES E INCOMPATIBILIDADES. El Procurador General, el Defensor General y el Asesor General de Incapaces, deben reunir las mismas condiciones que los Jueces de la Corte de Justicia ; duran seis años en el cargo pudiendo ser designados nuevamente y son nombrados y removidos de la misma manera que aquéllos. Los fiscales, defensores y asesores de incapaces, deben ser abogados, ciudadanos argentinos y cumplir con los demás requisitos que establece la ley, de acuerdo a la jerarquía que ésta determine y son designados, duran en el cargo y son removidos de la misma forma que los jueces inferiores. Tienen las mismas inmunidades, incompatibilidades e intangibilidad de las remuneraciones que éstos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 161, segments: [], amendments: [] },
  { id: 'const-salta-art-166', lawId: 'const-salta', number: '166', title: '', text: `Son sus atribuciones y deberes, las fijadas por la ley y especialmente: a) Promover la actuación de la justicia en defensa de la legalidad y de los intereses generales de la sociedad. b) Intervenir en toda causa judicial en que esté interesado el orden público. c) Velar por el respeto de los derechos, deberes, principios y garantías constitucionales, estando legitimado para demandar la inconstitucionalidadde toda ley, decreto, ordenanza, actos, contratos o resolución de cualquier autoridad pública provincial o municipal. d) Velar por la buena marcha de la administración de justicia y controlar el cumplimiento de los plazos procesales, estando facultado para acusar a los miembros del Poder Judicial y del Ministerio Público ante quien corresponda. e) Velar por el correcto cumplimiento de las leyes y garantías y de los derechos humanos en las cárceles y todo otro establecimiento de internación. f) Accionar en defensa y protección del medio ambiente e intereses difusos. g) Ejercer la acción penal en los delitos de acción pública. Asimismo ejercita las acciones para hacer efectiva la responsabilidad penal en que hubieren incurrido en perjuicio de la Administración Pública. h) Nombrar a sus empleados conforme a lo dispuesto en el`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 162, segments: [], amendments: [] },
  { id: 'const-salta-art-64-2', lawId: 'const-salta', number: '64', title: '', text: `Artículo 64 Inciso 2) de esta Constitución y removerlos. Los funcionarios letrados, son designados previo concurso público. i) Proponer y administrar su propio presupuesto, enviándolo al Poder Ejecutivo para su remisión al Poder Legislativo a efecto de su consideración. j) Tener iniciativa legislativa no exclusiva con respecto a la ley de organización del Ministerio Público, Códigos Procesales y demás leyes vinculadas a la administración de justicia y al ejercicio de sus funciones. k) Integrar el Consejo de la Magistratura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 163, segments: [], amendments: [] },
  { id: 'const-salta-art-167', lawId: 'const-salta', number: '167', title: 'Autonomia Funcional', text: `En el ejercicio de sus funciones el Ministerio Público es autónomo e independiente de los demás órganos del Poder Público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 164, segments: [], amendments: [] },
  { id: 'const-salta-art-168', lawId: 'const-salta', number: '168', title: '', text: `Los Poderes Públicos de la Provincia están obligados a prestar a este Ministerio la colaboración que requiera para el mejor cumplimiento de sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 165, segments: [], amendments: [] },
  { id: 'const-salta-art-169', lawId: 'const-salta', number: '169', title: 'De la Auditoria y Sindicatura General de la Provincia I', text: `Disposiciones Generales La Provincia de Salta sostiene un modelo de control de la hacienda pública integral e integrado. II. Auditoría Interna. Sindicatura General de la Provincia La Sindicatura General de la Provincia es el órgano de control interno presupuestario, contable, financiero, económico, patrimonial y legal de la Hacienda Pública Provincial centralizada y descentralizada, cualquiera fuere su modalidad de organización y evalúa las actividades y programas a ser ejecutados en la Provincia con caudales públicos. Su titular es el Síndico General de la Provincia, designado y removido por el Gobernador. Los restantes poderes y municipios fijan su procedimiento de control interno. La ley reglamenta su organización, funcionamiento y competencia. III. Auditoría General de la Provincia La Auditoría General de la Provincia es el órgano con independencia funcional, administrativa y financiera, competente para el control externo posterior y auditoría de la gestión económica, financiera, patrimonial, presupuestaria y operativa en atención a los criterios de legalidad, economía, eficiencia y eficacia de la Hacienda Pública Provincial y Municipal, incluyendo sus organismos descentralizados cualquiera fuese su modalidad de organización, empresas y sociedades del Estado, entes reguladores de servicios públicos y entes privados adjudicatarios de servicios privatizados en cuanto a las obligaciones emergentes de los respectivos contratos. Examina e informa a la Legislatura, aconsejando su aprobación o desaprobación sobre la Cuenta General del Ejercicio, cuentas de percepción e inversión de fondos públicos y de cualquiera de los estados contables que se elaboren por la Administración Pública Provincial y Municipal. Tiene legitimación para comparecer en juicio por sí misma y en representación del Estado, en los casos que se detecte, en virtud de las funciones atribuidas por esta Constitución y las leyes, posible daño patrimonial al Fisco. Los informes, dictámenes y pronunciamientos finales de la Auditoría, tienen la calidad de públicos y deben ser publicados por la misma. Las autoridades provinciales y los agentes y funcionarios del sector público provincial y municipal están obligados a proveerles la información que les requiera. Nombra su personal previo concurso público. Está conformada por cinco miembros, procurando su integración con criterio federal. Deben tener al menos treinta años de edad y diez años en el ejercicio de la profesión, título universitario en ciencias económicas, abogacía u otros graduados con especialización en administración financiera, control o auditoría. Son seleccionados por una Comisión de Auditoría de la Cámara de Diputados integrada por siete miembros, de los cuales cuatro deben pertenecer a los partidos políticos o frentes electorales de la oposición. La selección debe ponerse en conocimiento del plenario de la Cámara de Diputados. Son designados previa audiencia pública por la Cámara de Senadores en sesión pública. Duran ocho años en sus funciones no pudiendo ser designados nuevamente. Tienen las mismas incompatibilidades, gozan de las mismas inmunidades que las juezas y los jueces, y son removidos por las mismas causas que éstos mediante Juicio Político. La competencia, organización y funcionamiento son regulados por ley. (*)Punto III, párrafo 7°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 166, segments: [], amendments: [] },
  { id: 'const-salta-art-170', lawId: 'const-salta', number: '170', title: '', text: `LIMITES. Esta Constitución reconoce al Municipio como una comunidad natural que, asentada sobre un territorio y unida por relaciones de vecindad y arraigo, tiende a la búsqueda del bien común local. Los Municipios gozan de autonomía política, económica, financiera y administrativa. Para constituir un nuevo Municipio se requiere una población permanente de mil quinientos habitantes y una ley a tal efecto. Los Municipios existentes a la fecha de sanción de esta Constitución continúan revistiendo el carácter de tales. Para constituir un nuevo Municipio, se requiere una población permanente de tres mil habitantes y acreditar la sustentabilidad social, ambiental y económica de manera que garantice su desarrollo. Por razones de geopolítica, históricas o de área de frontera, se pueden constituir nuevos municipios con una cantidad menor de habitantes. Para todos los casos se requiere una ley a tal efecto. Los Municipios existentes a la fecha de sanción de esta Constitución continúan revistiendo el carácter de tales. Los Municipios pueden establecer Delegaciones Municipales. (*)Párrafo 2°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021) (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 167, segments: [], amendments: [] },
  { id: 'const-salta-art-171', lawId: 'const-salta', number: '171', title: '', text: `El Gobierno de los Municipios se compone de : 1) Un Departamento Ejecutivo a cargo de un Intendente que es elegido en forma directa y a simple mayoría de sufragios . 2) Un Concejo Deliberante, cuya integración se establece sobre la siguiente base poblacional: Hasta 5.000 habitantes 3 concejalas o concejales; De 5.001 a 1 5.000 habitantes 5 concejalas o concejales; De 1 5.001 a 30.000 habitantes 7 concejalas o concejales; De 30.001 a 50.000 habitantes 9 concejalas o concejales; De 50.001 en adelante 11 concejalas o concejales, más uno por cada 40.000 habitantes o fracción no inferior a 20.000 habitantes. La composición de los Concejos Deliberantes no puede exceder de veintiún miembros. (*)Inc. 2°: modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021). Fe de Erratas por B.O. 22/12/2021. (*)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 168, segments: [], amendments: [] },
  { id: 'const-salta-art-172', lawId: 'const-salta', number: '172', title: '', text: `DURACION . Para ser Concejala o Concejal se requiere: 1) Ser argentino nativo o naturalizado con cuatro años de ejercicio de la ciudadanía y estar inscripto en el registro cívico nacional o provincial. 2) Ser mayor de edad. 3) Ser vecino del Municipio con una residencia inmediata anterior de cuatro años o nativo del mismo. Para ser Intendenta o Intendente se debe tener veinticinco años de edad como mínimo, ser nativa o nativo del Municipio o tener cuatro años de residencia inmediata anterior en él y las demás condiciones para ser Concejala o Concejal. La Intendenta o el Intendente dura cuatro años en sus funciones y puede ser reelegido por un solo período consecutivo. Si ha sido reelecto no puede ser elegido, sino con el intervalo de un período. No pueden ser elegidos por un período inmediato al cese del cargo de Intendenta o Intendente sus parientes hasta el segundo grado, su cónyuge o con quien tenga unión convivencial. La Concejala o el Concejal dura cuatro años en sus funciones y puede ser reelegido por un solo período consecutivo. Si ha sido reelecto no puede ser elegido, sino con el intervalo de un período. Los Concejos Deliberantes que cuenten con al menos siete concejales se renuevan por mitades cada dos años; los que cuenten con menor número se renuevan en su totalidad conjuntamente con la elección de la Intendenta o del Intendente. (*)Modificado por Convención Constituyente (B.O. Edición Complementaria del 21/12/2021)`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 169, segments: [], amendments: [] },
  { id: 'const-salta-art-173', lawId: 'const-salta', number: '173', title: '', text: `El registro de los electores municipales se compone de: 1) Los inscriptos en el registro cívico electoral. 2) Los extranjeros, mayores de dieciocho años, con dos años de residencia inmediata en el municipio, al momento de su inscripción en el registro suplementario especial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 170, segments: [], amendments: [] },
  { id: 'const-salta-art-174', lawId: 'const-salta', number: '174', title: '', text: `LEYES DE MUNICIPALIDADES. Los Municipios de más de diez mil habitantes dictan su Carta Municipal, como la expresión de la voluntad del pueblo, en un todo de acuerdo con las disposiciones de esta Constitución. A tal efecto convocan a una Convención Municipal. Los miembros de la misma son electos por el sistema proporcional que fije la Ley Electoral, y su número no excede del doble de la composición del Concejo Deliberante. Para desempeñarse como Convencional deben reunirse los mismos requisitos exigidos para ser Concejal. La iniciativa para dictar o reformar la Carta Municipal corresponde al Intendente, al Concejo Deliberante o por iniciativa popular cuando reúna los requisitos legales. La declaración de necesidad requiere el voto de las dos terceras partes de los Miembros del Concejo Deliberante. Es condición de eficacia de las Cartas Municipales y de sus reformas, su previa aprobación por ley de la Provincia, a los efectos de su compatibilización. La Legislatura debe expedirse en un plazo máximo de ciento veinte días, transcurrido el cual sin que lo hiciera quedan automáticamente aprobadas. Los municipios de diez mil habitantes o menos, se rigen por las disposiciones de la Ley de Municipalidades. Sin perjuicio de ello, a pedido de cada Municipio, se contemplan sus situaciones particulares por una ley especial que se dicte a tal efecto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 171, segments: [], amendments: [] },
  { id: 'const-salta-art-175', lawId: 'const-salta', number: '175', title: '', text: `Constituyen recursos propios de los Municipios: 1) El impuesto a la propiedad inmobiliaria urbana. 2) Los impuestos cuya facultad de imposición corresponda por ley a las Municipalidades. 3) El impuesto a la radicación de automotores en los límites de cada uno de ellos. 4) Las tasas. 5) Las contribuciones por mejoras provenientes de obras municipales. 6) Las contraprestaciones por uso diferenciado de los bienes municipales. 7) La coparticipación en los impuestos que recaude la Nación o la Provincia con las alícuotas que fije la ley. 8) Los créditos, donaciones y subsidios. 9) Todos los demás ingresos determinados por las normas municipales en los límites de su competencia. Con parte de los recursos coparticipados se constituye un Fondo Compensador que adjudica la Legislatura por medio del Presupuesto, a los Municipios cuyos recursos resultaren insuficientes para atender los servicios a su cargo. La ley prevé sistemas de transferencia puntual y automática de los recursos en favor de los Municipios`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 172, segments: [], amendments: [] },
  { id: 'const-salta-art-176', lawId: 'const-salta', number: '176', title: '', text: `Compete a los Municipios sin perjuicio de las facultades provinciales, con arreglo a las Cartas Orgánicas y Leyes de Municipalidades : 1) Darse su propia organización normativa, económica, administrativa y financiera. 2) Aprobar su presupuesto, el que deberá ser elaborado dentro de un marco de disciplina fiscal, conforme a los principios de esta Constitución. 3) Establecer por Ordenanzas tasas y tarifas. 4) Recaudar e invertir sus recursos. Dar a publicidad por lo menos trimestralmente el estado de sus ingresos y egresos, y una memoria sobre la labor desarrollada, dentro de los sesenta días de vencido el ejercicio. 5) Contraer empréstitos con fines determinados, con la aprobación de los dos tercios de votos de la totalidad de los miembros del Concejo Deliberante. En ningún caso el servicio para el pago de empréstitos puede exceder la cuarta parte de las rentas municipales, ni la previsión financiera para tal objeto aplicarse a otros fines. 6) Prestar los servicios públicos locales por sí o por concesión. 7) La regulación de los cementerios y los servicios fúnebres. 8) La preservación del patrimonio histórico y arquitectónico local. 9) Lo relativo a urbanismo, higiene, salubridad y moralidad ; como así también a la protección y promoción del medio ambiente, paisaje, equilibrio ecológico y polución ambiental, tendiendo al desarrollo sostenible. 10) La recreación, deporte, esparcimiento y espectáculos públicos. 11) La realización de obras públicas. 12) El fomento de la educación, la cultura y el turismo. 13) La promoción en todos los niveles de la vida del Municipio de distintas formas y canales de participación de los vecinos, Entidades Intermedias y Gobierno Municipal. 14) Promover el desarrollo socio-económico local, tendiendo a la integración regional. 15) La cooperación con la Provincia o la Nación en asistencia social, salud pública, preservación del medio ambiente y recursos naturales. 16) Usar y disponer de sus bienes. Cuando se trate de gravar o enajenar bienes inmuebles, la aprobación del acto requiere el voto favorable de los dos tercios de la totalidad de los concejales. 17) Intervenir en su caso, en el supuesto del artículo 91 segundo párrafo. 18) Gestionar por vía judicial, luego de agotar la instancia administrativa, la cobranza de las rentas del municipio. 19) La iniciativa legislativa en materia de expropiación por causa de utilidad pública municipal. 20) La facultad de crear órganos de control y tribunales de faltas de conformidad a sus respectivas Cartas Orgánicas. 21) Celebrar convenios con otros Municipios, con la Provincia o la Nación, con empresas públicas o entidades autárquicas, con organismos nacionales e internacionales, en la esfera de su competencia. 22) Facultar al Intendente a ejecutar las políticas provinciales con recursos de tal origen que le asigne el Gobierno Provincial. 23) Dictar todas las Ordenanzas y reglamentos necesarios para el cumplimiento directo de sus fines.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 173, segments: [], amendments: [] },
  { id: 'const-salta-art-177', lawId: 'const-salta', number: '177', title: '', text: `De los fondos provenientes de la explotación de los recursos no renovables que perciba la Provincia, se adjudica a los Municipios donde se encuentren ubicados, un porcentaje establecido por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 174, segments: [], amendments: [] },
  { id: 'const-salta-art-178', lawId: 'const-salta', number: '178', title: '', text: `CONFLICTOS. DEMOCRACIA SEMI-DIRECTA. Las Cartas Municipales y la Ley de Municipalidades regulan las vías y procedimientos para asegurar la publicidad de todos los actos de los Municipios y la legal y apropiada inversión de sus recursos. Compete a la Corte de Justicia de la Provincia conocer en los conflictos entre los órganos ejecutivo y deliberativo de cada Municipio. Los electores municipales tienen los derechos de iniciativa y referéndum. Su ejercicio se rige por las disposiciones de la ley provincial que regula la práctica de las mencionadas formas de democracia semi-directa.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 175, segments: [], amendments: [] },
  { id: 'const-salta-art-179', lawId: 'const-salta', number: '179', title: '', text: `La Provincia puede intervenir a alguno o a todos los Poderes Municipales en los siguientes casos: 1) Acefalía total, para asegurar la inmediata constitución de sus autoridades. 2) Para normalizar una situación de crisis o gravedad institucional. 3) Cuando no se cumpla con el pago de los servicios de empréstitos, si en más de un ejercicio resulta un déficit susceptible de comprometer su estabilidad financiera o no preste adecuadamente los servicios públicos locales. 4) Por las demás causales que prevea la Carta Orgánica Municipal y la Ley de Municipalidades. La Legislatura dispone la intervención de un Municipio, por plazo determinado, mediante ley aprobada por el voto de los dos tercios de los miembros presentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 176, segments: [], amendments: [] },
  { id: 'const-salta-art-180', lawId: 'const-salta', number: '180', title: '', text: `INCOMPATIBILIDADES. El Intendente, los concejales y los convencionales municipales no pueden ser acusados, procesados, interrogados judicialmente, molestados ni reconvenidos por autoridad alguna, por las opiniones o votos que hayan emitido en el desempeño de sus cargos. Tienen iguales incompatibilidades que los legisladores, no siendo aplicables las disposiciones sobre licencias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 177, segments: [], amendments: [] },
  { id: 'const-salta-art-181', lawId: 'const-salta', number: '181', title: '', text: `Corresponde la destitución del Intendente por condena penal o por mal desempeño de su cargo. Para declarar la necesidad de su remoción se requiere los dos tercios de votos de la totalidad de los miembros del Concejo Deliberante. El Intendente puede apelar con efecto suspensivo ante la Corte de Justicia de la Provincia, la que debe expedirse en un plazo máximo de sesenta días contados a partir de la entrada del caso, el que se examina libremente con el más amplio poder de revisión y recepción de pruebas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 178, segments: [], amendments: [] },
  { id: 'const-salta-art-182', lawId: 'const-salta', number: '182', title: '', text: `En caso de ausencia o impedimento transitorios del Intendente, el Presidente del Concejo Deliberante lo reemplaza. Si la ausencia o inhabilidad es definitiva y falta más de un año para completar el período del mandato, debe convocarse a elecciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 179, segments: [], amendments: [] },
  { id: 'const-salta-art-183', lawId: 'const-salta', number: '183', title: '', text: `EXCLUSION. El Concejo Deliberante puede corregir a cualquiera de sus miembros por desorden de conducta en el ejercicio de sus funciones y hasta excluirlo de su seno por razones de incapacidad física o moral sobreviniente, debiendo para tal efecto concurrir los dos tercios de votos del total de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 180, segments: [], amendments: [] },
  { id: 'const-salta-art-184', lawId: 'const-salta', number: '184', title: '', text: `Esta Constitución puede reformarse en todo o en parte por una Convención convocada al efecto, siempre que la Legislatura declare la necesidad de la reforma con el voto de las dos terceras partes del total de los miembros de cada Cámara. Declarada tal necesidad la Presidencia del Senado la comunica al Poder Ejecutivo y al Tribunal Electoral y manda hacerla pública en toda la Provincia. El Poder Ejecutivo convoca a elección de convencionales, la que tiene lugar en el plazo mínimo de noventa días contados desde la publicación. En su caso, esta elección puede coincidir con la primera general que se realice en la Provincia. El Poder Ejecutivo puede instar la declaración de necesidad de reforma. La declaración de necesidad de reforma fija las materias sobre las que ésta debe versar y determina el plazo de duración de la convención. En el supuesto de reforma parcial la Convención Constituyente puede prorrogar sus sesiones por un tiempo igual a la mitad del plazo original ; en el supuesto de reforma total esta prórroga puede extenderse por un tiempo igual al originario. Si la Convención no cumpliere su cometido en el plazo legal y si se tratare de un supuesto de reforma total, todas sus sanciones son ineficaces. En el mismo supuesto, para el caso de reforma parcial son eficaces las sanciones realizadas dentro del plazo. Son nulas de nulidad absoluta todas las modificaciones, subrogaciones, derogaciones y agregados que realice la Convención Constituyente apartándose de las materias habilitadas por el Poder Legislativo, en ejercicio de la facultad preconstituyente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 181, segments: [], amendments: [] },
  { id: 'const-salta-art-185', lawId: 'const-salta', number: '185', title: '', text: `SU INSTALACION. QUORUM. SANCION Y PROMULGACION. La Convención Constituyente se compone de un número igual al de Diputados de la Provincia. Los Convencionales deben reunir las mismas condiciones que las exigidas para ser diputado y gozan de idénticas inmunidades. No existe incompatibilidad entre las funciones de convencional constituyente y cualquier otra de la Nación, la Provincia o los Municipios. La declaración de la necesidad de la reforma debe indicar la fecha del comienzo de las deliberaciones de la Convención; si nada se dijese, ésta debe constituirse en un plazo máximo de tres meses contados desde la elección popular. El quórum para sesionar es de la mayoría absoluta de la totalidad de sus miembros y sus decisiones se adoptan por simple mayoría. La Convención Constituyente sanciona, promulga y publica sus decisiones que deben ser observadas por todos como la expresión de la voluntad popular. Firmantes SAN MILLAN-SARAVIA DAY-DAHER-BARBARAN-ULIVARRI-IBARGUREN-DIAZ CLAUSULAS TRANSITORIAS PRIMERA : La presente Constitución entra en vigencia al día siguiente de su publicación, la que debe efectuarse dentro de los quince días de su sanción. Los miembros de la Convención Constituyente juran la presente antes de disolver el cuerpo. El Gobernador de la Provincia, los Presidentes de las Cámaras Legislativas y el Presidente de la Corte de Justicia prestan juramento ante la Convención Constituyente. Cada Poder del Estado dispone lo necesario para que los funcionarios integrantes de cada uno de éstos, juren esta Constitución. El día 25 de mayo de 1998, el pueblo de la Provincia es invitado a jurar fidelidad a la presente en actos públicos. SEGUNDA : Todas las normas de organización de los Poderes previstas en esta Constitución deben ser sancionadas o dictadas dentro del plazo de un año, salvo que tuvieren un plazo especial. Pendiente el dictado de dichas normas, continúan vigentes las actuales que no sean incompatibles con esta Constitución. TERCERA : El mandato del Gobernador y Vicegobernador en ejercicio al momento de sancionarse esta Reforma, es considerado como primer período. (corresponde al`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 182, segments: [], amendments: [] },
  { id: 'const-salta-art-140-2', lawId: 'const-salta', number: '140', title: '', text: `Artículo 140). CUARTA : Hasta tanto se dicte la ley de creación de Tribunales de Segunda Instancia en el fuero Contencioso - Administrativo, la Corte de Justicia entiende por vía recursiva en los juicios de expropiación y procesos administrativos. Es condición de admisibilidad de la demanda o acción, la previa denegación expresa o tácita por parte de la autoridad administrativa, de la pretensión, salvo cuando sea demandada la Provincia o sus entidades autárquicas como persona de derecho privado. QUINTA (Sancionada en 1986) : Declárase absolutamente nulo el Decreto N. 229/56 por el cual fue derogada la Constitución de 1949, sin perjuicio de la estabilidad de todos los actos jurídicos y de todas las decisiones de autoridad sancionadas con arreglo a la Constitución Provincial de 1929 entre 1956 y 1986. Derógase por esta vía legítima las Constituciones sancionadas en 1929 y 1949. SEXTA (Sancionada en 1986) : Mientras las comunas en condiciones de darse su propia Carta Municipal no lo hagan, se rigen por la Ley de Municipalidades. SEPTIMA (Sancionada en 1986 y ratificada en 1998) : La disposición contenida en el inciso 9) del artículo 144 se aplica a partir de la organización y establecimiento de los Juzgados competentes. OCTAVA : Hasta tanto se dicten las pertinentes leyes reglamentarias, subsisten los actuales regímenes legales y autoridades de entidades públicas cuya estructura y organización hayan sido materia de esta Constitución, salvo en los casos previstos en las demás normas transitorias. NOVENA : El Presidente de la Convención Constituyente, los Secretarios y los Prosecretarios del Cuerpo son los encargados de realizar todos los actos administrativos que reconozcan como origen el funcionamiento y disolución de la Convención. El Presidente de la Comisión Redactora juntamente con los Miembros de la Comisión de Labor Parlamentaria, tendrán a su cargo por mandato de la Asamblea : a) Efectuar el ordenamiento y revisión final del texto de la Constitución. b) Cuidar la publicación del mismo en el Boletín Oficial. c) Actuar en forma coadyuvante con el Presidente de la Convención en la realización de los actos previstos en el primer párrafo. La Comisión de Hacienda y Administración, por mandato del Cuerpo continúa integrada al efecto de realizar el control de traspaso de bienes, emitir dictamen definitivo sobre la ejecución presupuestaria y efectuar la aprobación final de los gastos por los períodos que no lo hubiese hecho el Cuerpo. Todos los actos enunciados en esta Disposición deben cumplirse en un plazo máximo e improrrogable hasta el 24 de abril del corriente año, y serán realizados en forma "ad honorem" por las personas designadas en la presente. DECIMA : A partir de la fecha de vigencia de esta Constitución los magistrados inferiores del Poder Judicial y los funcionarios del Ministerio Público solamente podrán ser designados por el procedimiento previsto en la presente con la intervención del Consejo de la Magistratura. La Legislatura deberá dictar la ley reglamentaria del Consejo de la Magistratura en el plazo de noventa días a partir de la vigencia de esta Constitución. DECIMO PRIMERA : El jurado de enjuiciamiento deberá integrarse como lo establece esta Constitución, dentro de los noventa días de sancionada la presente reforma. A tales efectos, los Poderes Públicos adoptarán los recaudos necesarios para designar sus representantes. En idéntico plazo deberá dictarse la ley reglamentaria y hasta tanto ello ocurra el Tribunal deberá juzgar con arreglo a los principios establecidos en esta Constitución y, en lo que sea compatible, con la ley actualmente vigente garantizando irrestrictamente el debido proceso. DECIMO SEGUNDA : Los actuales funcionarios del Ministerio Público duran en sus cargos el término por el que se les diera el acuerdo. Hasta tanto se dicte la ley de adecuación del Ministerio Público a la nueva estructura, éste será ejercido conforme al artículo 164 por el Procurador General, conjuntamente con los dos Fiscales ante la Corte de Justicia. DECIMO TERCERA (Sancionada en 1986) : Durante los próximos diez años a contar desde la sanción y promulgación de esta Constitución, se aplica el sistema electoral proporcional, conforme a las siguientes reglas : a) El total de votos obtenidos por cada lista, que haya alcanzado el 5% como mínimo de los votos válidos emitidos, es dividido por 1 (uno), por 2 (dos), por 3 (tres), y así sucesivamente hasta llegar al número de los cargos que se elijan. b) Los cocientes resultantes, con independencia de la lista de que provengan, son ordenados de mayor a menor en igual número de los cargos a cubrir. c) Si hay dos o más cocientes iguales se los ordena en relación directa con el total de votos obtenidos por las respectivas listas, y si han obtenido igual número de votos, se practica un sorteo. d) A cada lista le corresponden tantos cargos como veces sus cocientes figuren en el ordenamiento indicado en el inciso b). Transcurrido el plazo de diez años puede dictarse por ley un nuevo sistema, en su defecto continúa vigente el presente. DECIMO CUARTA : Habilítase a la Legislatura Provincial para que a través del procedimiento de la enmienda constitucional, que por única vez se instituye, modifique los artículos 56. y 94. de esta Constitución referidos a la integración y forma de elección de la Cámara de Diputados. Tal reforma deberá establecer un sistema electoral que asegure la igualdad del sufragio de los ciudadanos, la representación de las minorías y que la distribución de las bancas se haga en forma proporcional a los votos obtenidos por cada partido político. Establécese el siguiente procedimiento para la sanción de la enmienda: 1.- La iniciativa para presentarla se asigna a la Cámara de Diputados que actuará como Cámara de origen. 2.- Su aprobación requiere la mayoría absoluta de los presentes en la sesión de cada Cámara. 3.- Aprobada la iniciativa por la Cámara de Diputados, pasa al Senado y si éste no le introduce correcciones o adiciones la enmienda queda sancionada. 4.- Si el Senado le efectuare modificaciones vuelve la iniciativa a la Cámara de origen y si ésta insiste en su aprobación, por la mayoría absoluta de los presentes, queda sancionada la enmienda. 5.- Se promulga y publica automáticamente. 6.- La enmienda constitucional se aplicará en la elección que se practique para la renovación de las autoridades provinciales en el año 2003, rigiendo a partir de ese momento. La cláusula transitoria decimotercera de la Constitución de 1986 continúa en vigencia. Los Partidos Políticos con representación en la Convención Constituyente asumen el compromiso de impulsar en la Legislatura la sanción de la enmienda. (Corresponde al`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 183, segments: [], amendments: [] },
  { id: 'const-salta-art-184-2', lawId: 'const-salta', number: '184', title: '', text: `Artículo 184). DECIMO QUINTA (Sancionada en 1986) : Las disposiciones transitorias serán suprimidas del texto de esta Constitución en las sucesivas ediciones de la misma a medida que se dé cumplimiento a ellas, y pierdan su vigencia. DECIMO SEXTA : Hasta tanto se apruebe la Ley de Auditoría General de la Provincia, continúa funcionando el Tribunal de Cuentas de la Provincia con sus atribuciones y funciones y las autoridades designadas. Los Organos de Control establecidos por esta Constitución deberán conformar sus cuerpos profesional, técnico, administrativo y de servicios absorbiendo a tal efecto la totalidad del personal que desempeña tareas en el Tribunal de Cuentas. (Corresponde al`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 184, segments: [], amendments: [] },
  { id: 'const-salta-art-169-2', lawId: 'const-salta', number: '169', title: '', text: `Artículo 169). DECIMO SEPTIMA : Hasta tanto se reglamente el Hábeas Data, esta garantía se ejercerá a través de la Acción de Amparo. (Corresponde al`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 185, segments: [], amendments: [] },
  { id: 'const-salta-art-89-2', lawId: 'const-salta', number: '89', title: '', text: `Artículo 89). DECIMO OCTAVA : El informe previsto por el art. 144 inc. 6 ) será rendido en el año 1998 el día 1. de Mayo. DECIMO NOVENA : Acatando la voluntad popular esta Convención queda disuelta a las veinticuatro horas del día Miércoles 8 de Abril de 1998. NOMINA DE SEÑORES CONVENCIONALES CONSTITUYENTES ALVAREZ, María Teresa BARBERA, Eliseo BERNAL, Carlos Enrique BONAZZI, Laura Irene BRIZUELA MENDOZA, José Edmundo CABRERA, Samuel Eduardo CARDOZO, Néstor Fidel CARRILLO, Roberto CARRIZO, Carlos Eduardo CAUCOTA, Lorenzo CISNEROS DE LAVAQUE, Azucena CONTA, Walter Mario CORDOBA, Samuel Gerardo CORNEJO D\`ANDREA, Héctor CHAPAK, Fidela Alba DAHER, Zulema Beatriz DAKAK, José Humberto DALALE, Sara Victoria DE LOS RIOS, Pedro Máximo DE SAN ROMAN, Fernando S. ESCRIBAS, José Orlando ESPINOSA, Salustiano Crisóstomo ESTRADA DE PADILLA, Fabiana Marcela FERNANDEZ, Esteban Luis GALVAN, Enrique Antonio GALLO, Narciso Ramón GARCIA CASTIELLA, Pedro O. GISPERT, Susana Graciela GOMEZ DIEZ, Ricardo GONZALEZ, Carlos GRAMAGLIA, Roberto Enrique GUTIERREZ, Mirtha Delia HADDAD, Luis Alberto IBAÑEZ, Francisco IZURSA, Freddy JIMENEZ CABRERIZO, Manuel María LAPAD, Mirta LARA GROS, Guillermo Marcelo LEMIR SARAVIA, Juan Pablo LOUTAYF RANEA, Ricardo Eugenio MACHUCA, Fausto Ponciano MAIDANA, Elsa Ignacia MURATORE, Victoria ONTIVEROS, Alcides Leopoldo PARRA, Eduardo Oscar PEREZ ALSINA, Juan Agustín PEREZ, Adriana Del Valle PIEVE, Edmundo PIORNO, Claudio Apolinar QUIPILDOR, Horacio Martín RALLE DE MONTEROS, Delia Elena ROCHA ALFARO, Oscar N. SAN MILLAN, Julio Argentino SARAVIA TOLEDO, Fernando SARAVIA, Carlos Alberto SIMON, José Gustavo SOTO, Jorge Pablo TORINO, Miguel Angel ULIVARRI, Julia Elena WAYAR, Walter Raúl CONVENCION CONSTITUYENTE AUTORIDADES Presidente Dr. Julio Argentino San Millán Vicepresidente 1. Dr. Carlos Alberto Saravia Day Vicepresidente 2. Arq. Zulema Beatriz Daher Secretario Legislativo Dr. Carlos Arturo Ulivarri Secretario Administrativo Dr. Gustavo Enrique Barbarán Prosecretaria Legislativa Dra. Silvia Marcela Ibarguren Prosecretario Administrativo C.P.N. José Matías Jorge Díaz DECLARACIONES APROBADAS POR LA CONVENCION CONSTITUYENTE DE LA PROVINCIA DE SALTA DECLARACION N. 001 "Que esta Asamblea Constituyente vería con agrado que el Poder Legislativo de la provincia de Salta proceda a la modificación de la actual Ley 1349 de Municipalidades, reformada por Leyes 5814 y 6133, con el propósito de actualizar su contenido y adecuarlo a las previsiones contenidas en la Constitución Provincial introducidas por las reformas de los años 1986 y 1998, en lo referente al Régimen Municipal". SALA DE SESIONES, 03 de Abril de 1998 DECLARACION N. 002 "Que los sustantivos que indican funciones públicas en esta Constitución deben interpretarse como expresados en masculino y femenino". SALA DE SESIONES, 06 de Abril de 1998 Firmantes Dr. JULIO ARGENTINO SAN MILLAN Presidente Arq. ZULEMA BEATRIZ DAHER Vicepresidente 2. Dr. CARLOS ALBERTO SARAVIA DAY Vicepresidente 1. DR. GUSTAVO BARBARAN Secretario Administrativo Dr. CARLOS ARTURO ULIVARRI Secretario Legislativo Cr. JOSE MATIAS JORGE DIAZ Prosecretario Administrativo Dra. SILVIA MARCELA IBARGUREN Prosecretaria Legislativa Corresponde al texto aprobado por la Convención Constituyente, y a la renumeración y ordenamiento efectuados, lo que certificamos de acuerdo al mandato de la Novena Cláusula Transitoria. Salta, 17 de abril de 1998.-----------`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 186, segments: [], amendments: [] },
];
